import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import type { BankStatementDryRunRow, CustomerResolution } from '../../../../../services/kt/bankStatementImportModels';
import styles from './Step2DryRun.module.css';

interface ExpenseAssignmentModalProps {
  expenseRow: BankStatementDryRunRow;
  currentResolution?: CustomerResolution;
  onSave: (rowIndex: number, storeCode: string | null, storeName: string, isCommon: boolean) => void;
  onClose: () => void;
}

const ExpenseAssignmentModal: React.FC<ExpenseAssignmentModalProps> = ({
  expenseRow,
  currentResolution,
  onSave,
  onClose,
}) => {
  const currentStoreCode = currentResolution?.expenseStoreCode;
  const currentIsCommon = currentResolution?.isCommonExpense;
  const [selectedOption, setSelectedOption] = useState<'common' | 'store' | 'none'>(
    currentIsCommon ? 'common' : currentStoreCode ? 'store' : 'none'
  );
  const [storeInput, setStoreInput] = useState(currentStoreCode || '');

  return createPortal(
    <div className={styles.batchDetailOverlay} onClick={onClose}>
      <div className={styles.expenseModal} onClick={e => e.stopPropagation()}>
        <div className={styles.detailHeader}>
          <h3 className={styles.detailTitle}>Gán chi phí — Dòng #{expenseRow.rowIndex + 1}</h3>
          <button className={styles.detailClose} onClick={onClose}>✕</button>
        </div>
        <div className={styles.expenseModalBody}>
          <div style={{ marginBottom: 16, fontSize: 13, color: '#6b7280' }}>
            <strong>Nội dung:</strong> {expenseRow.description}<br />
            <strong>Số tiền:</strong> {expenseRow.amount?.toLocaleString('vi-VN')}₫
          </div>

          <div
            className={`${styles.expenseOption} ${selectedOption === 'none' ? styles.expenseOptionSelected : ''}`}
            onClick={() => setSelectedOption('none')}
          >
            <input type="radio" className={styles.expenseOptionRadio} checked={selectedOption === 'none'} readOnly />
            <div>
              <div className={styles.expenseOptionLabel}>Không gán chi phí</div>
              <div className={styles.expenseOptionDesc}>Giao dịch xử lý như bình thường (BC/UNC)</div>
            </div>
          </div>

          <div
            className={`${styles.expenseOption} ${selectedOption === 'common' ? styles.expenseOptionSelected : ''}`}
            onClick={() => setSelectedOption('common')}
          >
            <input type="radio" className={styles.expenseOptionRadio} checked={selectedOption === 'common'} readOnly />
            <div>
              <div className={styles.expenseOptionLabel}>Chi phí chung</div>
              <div className={styles.expenseOptionDesc}>Phân bổ vào chi phí chung (POOL/HEAD)</div>
            </div>
          </div>

          <div
            className={`${styles.expenseOption} ${selectedOption === 'store' ? styles.expenseOptionSelected : ''}`}
            onClick={() => setSelectedOption('store')}
          >
            <input type="radio" className={styles.expenseOptionRadio} checked={selectedOption === 'store'} readOnly />
            <div>
              <div className={styles.expenseOptionLabel}>Gán cho cửa hàng</div>
              <div className={styles.expenseOptionDesc}>Nhập mã cửa hàng hoặc nhóm cửa hàng</div>
              {selectedOption === 'store' && (
                <input
                  type="text"
                  className={styles.storeInput}
                  value={storeInput}
                  onChange={e => setStoreInput(e.target.value)}
                  placeholder="Nhập mã cửa hàng (VD: FM01, REVA_POOL...)"
                  autoFocus
                  onClick={e => e.stopPropagation()}
                />
              )}
            </div>
          </div>
        </div>

        <div style={{ padding: '12px 20px', borderTop: '1px solid #e5e7eb', display: 'flex', justifyContent: 'flex-end', gap: 8 }}>
          <button className={styles.secondaryBtn} onClick={onClose}>Huỷ</button>
          <button
            className={styles.primaryBtn}
            disabled={selectedOption === 'store' && !storeInput.trim()}
            onClick={() => {
              if (selectedOption === 'common') {
                onSave(expenseRow.rowIndex, null, 'Chi phí chung', true);
              } else if (selectedOption === 'store' && storeInput.trim()) {
                onSave(expenseRow.rowIndex, storeInput.trim(), storeInput.trim(), false);
              } else {
                onSave(expenseRow.rowIndex, null, '', false);
              }
            }}
          >
            Xác nhận
          </button>
        </div>
      </div>
    </div>,
    document.body,
  );
};

export default ExpenseAssignmentModal;
