import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import type { BankStatementImportRow, FileSlotInfo, BatchDetailLine } from '../../../../../services/kt/bankStatementImportModels';
import { POSTING_CATEGORIES, KIND_BG, KIND_TEXT } from '../../../../../services/kt/bankStatementPostingRules';
import { extractBulkRefsFromDescription, normalizeBulkRef } from '../../../../../utils/extractBatchRefs';
import styles from './Step1Upload.module.css';

// ── Types ─────────────────────────────────────────────────────────────────────

interface ParseProgress {
  fileName: string;
  loaded: number;
  total: number;
}

/** File mới bị trùng tên với file đã có trong danh sách. */
interface ConflictItem {
  file: File;
  /** Index của file đang tồn tại trong bankStatements. */
  existingIndex: number;
  existingName: string;
  /** Quyết định của user: 'skip' | 'override'. undefined = chưa chọn. */
  resolution: 'skip' | 'override' | undefined;
}

interface Step1UploadProps {
  bankStatements: FileSlotInfo[];
  batchPayments: File[];
  skipEmptyRows: boolean;
  onSkipEmptyRowsChange: (skip: boolean) => void;
  /** Thêm file mới. `overrideIndices` là index các file cũ cần xoá trước khi add. */
  onBankStatementSelect: (files: File[], overrideIndices?: number[]) => void;
  onBankStatementRemove: (index: number) => void;
  onBatchPaymentAdd: (files: File[]) => void;
  onBatchPaymentRemove: (index: number) => void;
  /**
   * Folder import từ bất kỳ zone nào — tự detect file loại và route đúng zone.
   * Gọi khi user chọn folder input hoặc drop folder (không phải file đơn lẻ).
   */
  onSmartFolderImport: (files: File[]) => void;
  onNext: () => void;
  /** Progressive parse progress — null khi không đang parse. */
  parseProgress?: ParseProgress | null;
  /** Partial rows đã parse (cập nhật theo chunk — hiển thị line-by-line). */
  partialRows?: BankStatementImportRow[];
  /** Files auto-detect là thanh toán lô — đang chờ user xác nhận chuyển. */
  bulkDetectedFiles?: File[];
  /** User xác nhận chuyển sang batch payment. */
  onBulkConfirm?: (files: File[]) => void;
  /** User từ chối — bỏ qua. */
  onBulkReject?: () => void;
  /** Chi tiết các file thanh toán lô đã parse (cho tab preview). */
  parsedBatchPaymentDetails?: { file: File; lines: BatchDetailLine[] }[];
}

// ── Constants ─────────────────────────────────────────────────────────────────

// Không dùng template label — hiển thị Hợp lệ / Không hợp lệ thay thế.

const ALLOWED_EXT = ['.xlsx', '.csv', '.xls'];

// ── Helpers — Folder reading ──────────────────────────────────────────────────

/** Đọc toàn bộ entries từ một DirectoryReader (readEntries trả max 100 mỗi lần). */
function readAllEntries(reader: FileSystemDirectoryReader): Promise<FileSystemEntry[]> {
  return new Promise((resolve, reject) => {
    const all: FileSystemEntry[] = [];
    const readBatch = () => {
      reader.readEntries((entries) => {
        if (entries.length === 0) {
          resolve(all);
        } else {
          all.push(...entries);
          readBatch(); // Tiếp tục đọc batch tiếp theo
        }
      }, reject);
    };
    readBatch();
  });
}

/** Đệ quy đọc tất cả file từ một FileSystemEntry (có thể là file hoặc folder). */
async function readFilesFromEntry(entry: FileSystemEntry): Promise<File[]> {
  if (entry.isFile) {
    return new Promise<File[]>((resolve, reject) => {
      (entry as FileSystemFileEntry).file((f) => resolve([f]), reject);
    });
  }
  if (entry.isDirectory) {
    const reader = (entry as FileSystemDirectoryEntry).createReader();
    const entries = await readAllEntries(reader);
    const nested = await Promise.all(entries.map(readFilesFromEntry));
    return nested.flat();
  }
  return [];
}

/** Lọc chỉ giữ các file có extension hỗ trợ. */
function filterSupportedFiles(files: File[]): File[] {
  return files.filter(f =>
    ALLOWED_EXT.some(ext => f.name.toLowerCase().endsWith(ext))
  );
}

function formatAmount(n?: number): string {
  if (n == null) return '—';
  return n.toLocaleString('vi-VN');
}

// ── TxPanel — panel một chiều Thu/Chi (self-contained state) ─────────────────

const PANEL_PAGE = 50;

type TxRow = BankStatementImportRow & { postingCategoryCode?: string; postingCategoryLabel?: string };

interface TxPanelProps {
  title: string;
  rows: BankStatementImportRow[];
  accentColor: string;   // màu số tiền
  emptyText: string;
  isParsing: boolean;
}

const TxPanel: React.FC<TxPanelProps> = ({ title, rows, accentColor, emptyText, isParsing }) => {
  const [activeCard, setActiveCard] = useState<string | null>(null);
  const [visibleCount, setVisibleCount] = useState(PANEL_PAGE);
  const sentinelRef = useRef<HTMLDivElement>(null);

  // Reset khi data thay đổi (đổi file, đổi parse)
  useEffect(() => {
    setActiveCard(null);
    setVisibleCount(PANEL_PAGE);
  }, [rows.length]);

  // Reset khi đổi filter
  useEffect(() => {
    setVisibleCount(PANEL_PAGE);
  }, [activeCard]);

  const statGroups = useMemo(() => {
    const orderedCodes = POSTING_CATEGORIES.map(c => c.code);
    const map = new Map<string, { label: string; kind: string; count: number; total: number }>();
    for (const r of rows as TxRow[]) {
      const code = r.postingCategoryCode ?? 'CHUA_PHAN_LOAI';
      const label = r.postingCategoryLabel ?? 'Chưa phân loại';
      if (!map.has(code)) {
        map.set(code, { label, kind: POSTING_CATEGORIES.find(c => c.code === code)?.kind ?? 'unknown', count: 0, total: 0 });
      }
      const e = map.get(code)!;
      e.count += 1;
      e.total += r.amount ?? 0;
    }
    const known = orderedCodes.filter(c => map.has(c)).map(c => ({ code: c, ...map.get(c)! }));
    const extra = [...map.entries()].filter(([c]) => !orderedCodes.includes(c)).map(([c, v]) => ({ code: c, ...v }));
    return [...known, ...extra];
  }, [rows]);

  const filtered = useMemo(() => {
    if (!activeCard) return rows as TxRow[];
    return (rows as TxRow[]).filter(r => (r.postingCategoryCode ?? 'CHUA_PHAN_LOAI') === activeCard);
  }, [rows, activeCard]);

  // IntersectionObserver — load-more
  useEffect(() => {
    const el = sentinelRef.current;
    if (!el || visibleCount >= filtered.length) return;
    const obs = new IntersectionObserver(
      (entries) => { if (entries[0].isIntersecting) setVisibleCount(prev => Math.min(prev + PANEL_PAGE, filtered.length + PANEL_PAGE)); },
      { rootMargin: '200px' },
    );
    obs.observe(el);
    return () => obs.disconnect();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visibleCount, filtered.length]);

  const totalAmount = rows.reduce((s, r) => s + (r.amount ?? 0), 0);

  return (
    <div className={styles.txPanel}>
      {/* Header */}
      <div className={styles.txPanelHeader}>
        <span className={styles.txPanelTitle}>{title}</span>
        <span className={styles.txPanelCount}>{rows.length.toLocaleString('vi-VN')}</span>
        <span className={styles.txPanelTotal} style={{ color: accentColor }}>
          {formatAmount(totalAmount)}
        </span>
        {isParsing && <span className={styles.liveIndicator}>● LIVE</span>}
      </div>

      {/* Stat cards */}
      {statGroups.length > 0 && (
        <div className={styles.panelStatRow}>
          <button
            className={`${styles.panelStatCard} ${!activeCard ? styles.panelStatCardActive : ''}`}
            onClick={() => setActiveCard(null)}
          >
            <span className={styles.panelStatLabel}>Tất cả</span>
            <span className={styles.panelStatCount}>{rows.length.toLocaleString('vi-VN')}</span>
          </button>
          {statGroups.map(g => {
            const bg = KIND_BG[g.kind as keyof typeof KIND_BG] ?? '#f3f4f6';
            const fg = KIND_TEXT[g.kind as keyof typeof KIND_TEXT] ?? '#374151';
            const on = activeCard === g.code;
            return (
              <button
                key={g.code}
                className={`${styles.panelStatCard} ${on ? styles.panelStatCardActive : ''}`}
                style={on ? { borderColor: fg, background: bg + '55' } : undefined}
                onClick={() => setActiveCard(prev => prev === g.code ? null : g.code)}
              >
                <span className={styles.panelStatLabel}>{g.label}</span>
                <span className={styles.panelStatCount} style={on ? { color: fg } : undefined}>
                  {g.count.toLocaleString('vi-VN')}
                </span>
              </button>
            );
          })}
        </div>
      )}

      {/* Filter bar */}
      {activeCard && (
        <div className={styles.filterBar}>
          <span><strong>{statGroups.find(g => g.code === activeCard)?.label ?? activeCard}</strong> · {filtered.length.toLocaleString('vi-VN')} gd</span>
          <button className={styles.clearFilterBtn} onClick={() => setActiveCard(null)}>✕</button>
        </div>
      )}

      {/* Grid */}
      <div className={styles.gridWrap}>
        {filtered.length === 0 ? (
          <div className={styles.gridEmpty}>{emptyText}</div>
        ) : (
          <>
            <table className={styles.categoryTable}>
              <thead>
                <tr>
                  <th className={styles.categoryTh} style={{ width: 30 }}>#</th>
                  <th className={styles.categoryTh} style={{ width: 82 }}>Ngày</th>
                  <th className={styles.categoryTh}>Đối tác</th>
                  <th className={styles.categoryTh} style={{ width: 110, textAlign: 'right' }}>Số tiền</th>
                  <th className={styles.categoryTh}>Nội dung</th>
                  <th className={styles.categoryTh} style={{ width: 100 }}>Mã tham chiếu</th>
                  <th className={styles.categoryTh} style={{ width: 115 }}>Nghiệp vụ</th>
                </tr>
              </thead>
              <tbody>
                {filtered.slice(0, visibleCount).map(row => {
                  const catEntry = POSTING_CATEGORIES.find(c => c.code === (row.postingCategoryCode ?? 'CHUA_PHAN_LOAI'));
                  const chipBg = KIND_BG[catEntry?.kind ?? 'unknown'] ?? '#f3f4f6';
                  const chipFg = KIND_TEXT[catEntry?.kind ?? 'unknown'] ?? '#6b7280';
                  return (
                    <tr key={row.rowIndex} className={styles.categoryTr}>
                      <td className={styles.categoryTd} style={{ color: '#9ca3af', fontSize: 10 }}>{row.rowIndex + 1}</td>
                      <td className={styles.categoryTd} style={{ whiteSpace: 'nowrap', fontSize: 11 }}>{row.transactionDate ?? '—'}</td>
                      <td className={styles.categoryTd} style={{ maxWidth: 0 }}>
                        {row.counterpartyName
                          ? <div className={styles.descEllipsis} style={{ fontWeight: 500 }} title={row.counterpartyName}>{row.counterpartyName}</div>
                          : <span style={{ color: '#9ca3af', fontSize: 11 }}>—</span>
                        }
                        {row.bankAccountCode && (
                          <div className={styles.descSub} style={{ fontFamily: 'monospace' }}>{row.bankAccountCode}</div>
                        )}
                      </td>
                      <td className={styles.categoryTd} style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums', fontWeight: 600, color: accentColor, fontSize: 12 }}>
                        {formatAmount(row.amount)}
                      </td>
                      <td className={styles.categoryTd} style={{ maxWidth: 0 }}>
                        <div className={styles.descEllipsis} style={{ fontSize: 11, color: '#374151' }} title={row.description ?? ''}>
                          {row.description ?? '—'}
                        </div>
                      </td>
                      <td className={styles.categoryTd} style={{ fontSize: 11, color: '#9ca3af', fontFamily: 'monospace', whiteSpace: 'nowrap' }}>
                        {row.referenceCode ?? '—'}
                      </td>
                      <td className={styles.categoryTd}>
                        <span className={styles.categoryChip} style={{ background: chipBg, color: chipFg }}>
                          {row.postingCategoryLabel ?? 'Chưa PL'}
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>

            {visibleCount < filtered.length && (
              <div ref={sentinelRef} className={styles.loadMoreSentinel}>
                <span className={styles.loadMoreLabel}>
                  {visibleCount.toLocaleString('vi-VN')} / {filtered.length.toLocaleString('vi-VN')}…
                </span>
              </div>
            )}
            {visibleCount >= filtered.length && filtered.length > PANEL_PAGE && (
              <div className={styles.allLoadedNote}>✓ {filtered.length.toLocaleString('vi-VN')} giao dịch</div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

// ── BatchPanel — grid scroll Tháng → Ngày × Ngân hàng → Chi tiết ───────────

const BATCH_PAGE = 50;

interface BatchPanelProps {
  details: { file: File; lines: BatchDetailLine[] }[];
}

type CellKey = { sortKey: string; bank: string };

const BatchPanel: React.FC<BatchPanelProps> = ({ details }) => {
  const [activeMonth, setActiveMonth] = useState<string | null>(null); // "MM/YYYY"
  const [activeBank, setActiveBank] = useState<string | null>(null);   // header click
  const [activeCell, setActiveCell] = useState<CellKey | null>(null);  // cell click
  const [visibleCount, setVisibleCount] = useState(BATCH_PAGE);
  const sentinelRef = useRef<HTMLDivElement>(null);

  // Flat tất cả lines (không filter theo file — file selector bị xoá để tránh trùng)
  const allLines = useMemo(() => details.flatMap(d => d.lines), [details]);

  // Reset khi data thay đổi
  useEffect(() => {
    setActiveMonth(null); setActiveBank(null); setActiveCell(null); setVisibleCount(BATCH_PAGE);
  }, [allLines.length]);
  useEffect(() => { setVisibleCount(BATCH_PAGE); }, [activeMonth, activeBank, activeCell]);

  // Detect cùng năm → chỉ show DD/MM
  const sameYear = useMemo(() => {
    const years = new Set(allLines.map(l => l.sheetDate?.split('/')[2]).filter(Boolean));
    return years.size <= 1 ? [...years][0] ?? null : null;
  }, [allLines]);

  // Month stats — key "MM/YYYY", label "T01"/"T01/26"
  const months = useMemo(() => {
    const map = new Map<string, { label: string; count: number; amount: number }>();
    for (const l of allLines) {
      const parts = l.sheetDate?.split('/');
      if (!parts || parts.length !== 3) continue;
      const key = `${parts[1]}/${parts[2]}`;
      const label = sameYear ? `T${parts[1]}` : `T${parts[1]}/${parts[2].slice(-2)}`;
      if (!map.has(key)) map.set(key, { label, count: 0, amount: 0 });
      const e = map.get(key)!;
      e.count++;
      e.amount += l.amount;
    }
    return [...map.entries()]
      .sort(([a], [b]) => {
        const [am, ay] = a.split('/');
        const [bm, by] = b.split('/');
        return `${ay}${am}`.localeCompare(`${by}${bm}`);
      })
      .map(([key, v]) => ({ key, ...v }));
  }, [allLines, sameYear]);

  // Lines thuộc tháng được chọn (hoặc tất cả)
  const monthLines = useMemo(() => {
    if (!activeMonth) return allLines;
    return allLines.filter(l => {
      const parts = l.sheetDate?.split('/');
      return parts && parts.length === 3 && `${parts[1]}/${parts[2]}` === activeMonth;
    });
  }, [allLines, activeMonth]);

  // Banks từ monthLines, sort count desc
  const banks = useMemo(() => {
    const map = new Map<string, number>();
    for (const l of monthLines) {
      const k = l.bankName || 'Khác';
      map.set(k, (map.get(k) || 0) + 1);
    }
    return [...map.entries()].sort((a, b) => b[1] - a[1]).map(([b]) => b);
  }, [monthLines]);

  // Day × Bank grid — LUÔN hiện (kể cả "Tất cả" mode)
  type CellData = { count: number; amount: number };
  type GridRow = { sortKey: string; display: string; bankMap: Map<string, CellData> };
  const dayGrid = useMemo((): GridRow[] => {
    const map = new Map<string, GridRow>();
    for (const l of monthLines) {
      const parts = l.sheetDate?.split('/');
      if (!parts || parts.length !== 3) continue;
      const [dd, mm, yyyy] = parts;
      const sortKey = `${yyyy}-${mm.padStart(2, '0')}-${dd.padStart(2, '0')}`;
      const display = sameYear ? `${dd.padStart(2, '0')}/${mm}` : `${dd.padStart(2, '0')}/${mm}/${yyyy.slice(-2)}`;
      const bank = l.bankName || 'Khác';
      if (!map.has(sortKey)) map.set(sortKey, { sortKey, display, bankMap: new Map() });
      const row = map.get(sortKey)!;
      if (!row.bankMap.has(bank)) row.bankMap.set(bank, { count: 0, amount: 0 });
      const cell = row.bankMap.get(bank)!;
      cell.count++;
      cell.amount += l.amount;
    }
    return [...map.values()].sort((a, b) => a.sortKey.localeCompare(b.sortKey));
  }, [monthLines, sameYear]);

  // Filtered lines cho detail grid
  const filteredLines = useMemo(() => {
    let rows = monthLines;
    if (activeBank) {
      // Header click → filter by bank (tất cả ngày)
      rows = rows.filter(l => (l.bankName || 'Khác') === activeBank);
    } else if (activeCell) {
      // Cell click → filter by date + bank
      rows = rows.filter(l => {
        const parts = l.sheetDate?.split('/');
        if (!parts || parts.length !== 3) return false;
        const [dd, mm, yyyy] = parts;
        const sk = `${yyyy}-${mm.padStart(2, '0')}-${dd.padStart(2, '0')}`;
        return sk === activeCell.sortKey && (l.bankName || 'Khác') === activeCell.bank;
      });
    }
    return rows;
  }, [monthLines, activeBank, activeCell]);

  // Format ngày
  const fmtLineDate = (d?: string) => {
    if (!d) return '—';
    const parts = d.split('/');
    if (parts.length !== 3) return d;
    return sameYear ? `${parts[0]}/${parts[1]}` : d;
  };

  // Infinite scroll
  useEffect(() => {
    const el = sentinelRef.current;
    if (!el || visibleCount >= filteredLines.length) return;
    const obs = new IntersectionObserver(
      entries => { if (entries[0].isIntersecting) setVisibleCount(p => Math.min(p + BATCH_PAGE, filteredLines.length + BATCH_PAGE)); },
      { rootMargin: '200px' },
    );
    obs.observe(el);
    return () => obs.disconnect();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visibleCount, filteredLines.length]);

  if (details.length === 0) {
    return (
      <div className={styles.contentEmpty}>
        <div className={styles.contentEmptyIcon}>📦</div>
        <div className={styles.contentEmptyText}>Chưa có file thanh toán lô</div>
      </div>
    );
  }

  const totalAmount = allLines.reduce((s, l) => s + l.amount, 0);

  return (
    <div className={styles.txPanel}>
      {/* Header tổng */}
      <div className={styles.txPanelHeader}>
        <span className={styles.txPanelTitle}>Thanh toán lô</span>
        <span className={styles.txPanelCount}>{allLines.length.toLocaleString('vi-VN')} GD</span>
        <span className={styles.txPanelTotal} style={{ color: '#7c3aed' }}>{formatAmount(totalAmount)}</span>
      </div>

      {/* ── Month stats row (không show file selector — tránh trùng) ─── */}
      <div className={styles.batchMonthRow}>
        <button
          className={`${styles.batchMonthCell} ${!activeMonth ? styles.batchMonthCellActive : ''}`}
          onClick={() => { setActiveMonth(null); setActiveBank(null); setActiveCell(null); }}
        >
          <span className={styles.batchMonthLabel}>Tất cả</span>
          <span className={styles.batchMonthCount}>{allLines.length.toLocaleString('vi-VN')}</span>
        </button>
        {months.map(m => (
          <button
            key={m.key}
            className={`${styles.batchMonthCell} ${activeMonth === m.key ? styles.batchMonthCellActive : ''}`}
            onClick={() => {
              setActiveMonth(prev => prev === m.key ? null : m.key);
              setActiveBank(null); setActiveCell(null);
            }}
            title={formatAmount(m.amount)}
          >
            <span className={styles.batchMonthLabel}>{m.label}</span>
            <span className={styles.batchMonthCount}>{m.count.toLocaleString('vi-VN')}</span>
          </button>
        ))}
      </div>

      {/* ── Day × Bank pivot grid (luôn hiện) ──────────────────────── */}
      {dayGrid.length > 0 && (
        <div className={styles.dayBankGridWrap}>
          <table className={styles.dayBankGrid}>
            <thead>
              <tr>
                <th className={styles.dayBankThDay}>Ngày</th>
                {banks.map(b => (
                  <th
                    key={b}
                    className={`${styles.dayBankThBank} ${activeBank === b ? styles.dayBankThBankActive : ''}`}
                    title={b}
                    onClick={() => {
                      setActiveBank(prev => prev === b ? null : b);
                      setActiveCell(null);
                    }}
                  >
                    {b.length > 14 ? `${b.slice(0, 13)}…` : b}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {dayGrid.map(row => (
                <tr key={row.sortKey} className={styles.dayBankTr}>
                  <td className={styles.dayBankTdDay}>{row.display}</td>
                  {banks.map(bank => {
                    const cell = row.bankMap.get(bank);
                    const isActive = activeCell?.sortKey === row.sortKey && activeCell?.bank === bank;
                    const isBankActive = activeBank === bank;
                    return (
                      <td
                        key={bank}
                        className={`${styles.dayBankTd} ${cell ? styles.dayBankTdHas : styles.dayBankTdEmpty} ${isActive ? styles.dayBankTdActive : ''} ${isBankActive && cell ? styles.dayBankTdBankHl : ''}`}
                        onClick={() => {
                          if (!cell) return;
                          setActiveCell(prev =>
                            prev?.sortKey === row.sortKey && prev?.bank === bank
                              ? null
                              : { sortKey: row.sortKey, bank }
                          );
                          setActiveBank(null);
                        }}
                        title={cell ? `${bank} · ${row.display}: ${cell.count} GD · ${formatAmount(cell.amount)}` : undefined}
                      >
                        {cell ? cell.count : ''}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Filter context bar */}
      {(activeMonth || activeBank || activeCell) && (
        <div className={styles.filterBar}>
          <span>
            {activeMonth && <strong>{months.find(m => m.key === activeMonth)?.label ?? activeMonth}</strong>}
            {activeBank && <>{activeMonth ? ' · ' : ''}<strong>{activeBank}</strong> (tất cả ngày)</>}
            {activeCell && <>{activeMonth ? ' · ' : ''}{dayGrid.find(r => r.sortKey === activeCell.sortKey)?.display} · <strong>{activeCell.bank}</strong></>}
            {' '}— {filteredLines.length.toLocaleString('vi-VN')} GD · {formatAmount(filteredLines.reduce((s, l) => s + l.amount, 0))}
          </span>
          <button className={styles.clearFilterBtn} onClick={() => { setActiveMonth(null); setActiveBank(null); setActiveCell(null); }}>✕</button>
        </div>
      )}

      {/* ── Detail grid (scrollable) ────────────────────────────── */}
      <div className={styles.gridWrap}>
        {filteredLines.length === 0 ? (
          <div className={styles.gridEmpty}>Không có dữ liệu</div>
        ) : (
          <>
            <table className={styles.categoryTable}>
              <thead>
                <tr>
                  <th className={styles.categoryTh} style={{ width: 30 }}>#</th>
                  <th className={styles.categoryTh} style={{ width: 52 }}>Ngày</th>
                  <th className={styles.categoryTh}>Người thụ hưởng</th>
                  <th className={styles.categoryTh} style={{ width: 120 }}>Số TK</th>
                  <th className={styles.categoryTh} style={{ width: 110, textAlign: 'right' }}>Số tiền</th>
                  <th className={styles.categoryTh}>Nội dung CK</th>
                  <th className={styles.categoryTh} style={{ width: 110 }}>Mã FT</th>
                  <th className={styles.categoryTh} style={{ width: 80 }}>Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                {filteredLines.slice(0, visibleCount).map((line, idx) => {
                  const statusOk = !!(line.status && (
                    line.status.toLowerCase().includes('th\u00e0nh c\u00f4ng') ||
                    line.status.toLowerCase().includes('success')
                  ));
                  const statusErr = !!(line.status && (
                    line.status.toLowerCase().includes('l\u1ed7i') ||
                    line.status.toLowerCase().includes('fail')
                  ));
                  return (
                    <tr key={idx} className={styles.categoryTr}>
                      <td className={styles.categoryTd} style={{ color: '#9ca3af', fontSize: 10 }}>{line.lineIndex + 1}</td>
                      <td className={styles.categoryTd} style={{ fontSize: 11, color: '#2563eb', whiteSpace: 'nowrap' }}>
                        {fmtLineDate(line.sheetDate)}
                      </td>
                      <td className={styles.categoryTd}>
                        <div className={styles.descEllipsis} style={{ fontWeight: 500 }}>{line.beneficiaryName || '—'}</div>
                        {line.bankName && <div className={styles.descSub}>{line.bankName}</div>}
                      </td>
                      <td className={styles.categoryTd} style={{ fontSize: 11, color: '#4b5563', fontFamily: 'monospace' }}>
                        {line.accountNumber ?? '—'}
                      </td>
                      <td className={styles.categoryTd} style={{ textAlign: 'right', fontWeight: 700, color: '#7c3aed', fontSize: 12 }}>
                        {formatAmount(line.amount)}
                      </td>
                      <td className={styles.categoryTd} style={{ maxWidth: 0 }}>
                        <div className={styles.descEllipsis} style={{ fontSize: 11, color: '#374151' }}>
                          {line.description ?? '—'}
                        </div>
                      </td>
                      <td className={styles.categoryTd} style={{ fontSize: 10, color: '#9ca3af', fontFamily: 'monospace', wordBreak: 'break-all' }}>
                        {line.ftNumber ?? '—'}
                      </td>
                      <td className={styles.categoryTd}>
                        {line.status ? (
                          <span className={styles.categoryChip} style={{
                            background: statusOk ? '#dcfce7' : statusErr ? '#fee2e2' : '#f3f4f6',
                            color: statusOk ? '#15803d' : statusErr ? '#b91c1c' : '#6b7280',
                            fontSize: 10,
                          }}>
                            {statusOk ? '✓' : statusErr ? '✗' : ''} {line.status}
                          </span>
                        ) : '—'}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
            {visibleCount < filteredLines.length && (
              <div ref={sentinelRef} className={styles.loadMoreSentinel}>
                <span className={styles.loadMoreLabel}>
                  {visibleCount.toLocaleString('vi-VN')} / {filteredLines.length.toLocaleString('vi-VN')}…
                </span>
              </div>
            )}
            {visibleCount >= filteredLines.length && filteredLines.length > BATCH_PAGE && (
              <div className={styles.allLoadedNote}>✓ {filteredLines.length.toLocaleString('vi-VN')} giao dịch</div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

// ── BatchReconcilePanel — đối soát mã GD lô ↔ sao kê (1 GD ↔ nhiều lô) ───────

interface BatchReconcileProps {
  /** Tất cả dòng sao kê đã parse. */
  saoke: BankStatementImportRow[];
  /** Chi tiết các file thanh toán lô đã parse. */
  batches: { file: File; lines: BatchDetailLine[] }[];
}

type BRecGroup = {
  batchRef: string;
  sheetDate?: string;
  fileName: string;
  lineCount: number;
  totalAmount: number;
  lines: BatchDetailLine[];
};

const BatchReconcilePanel: React.FC<BatchReconcileProps> = ({ saoke, batches }) => {
  /** Manual: batchRef → saoke rowIndex. Cùng 1 rowIndex có thể gắn nhiều batchRef. */
  const [manualMap, setManualMap] = useState<Record<string, number>>({});
  /** Auto-map bị user bỏ gắn — không resolve lại từ description. */
  const [suppressedAuto, setSuppressedAuto] = useState<Record<string, true>>({});
  const [lookupOpen, setLookupOpen] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterMode, setFilterMode] = useState<'all' | 'mapped' | 'mismatched' | 'unmapped'>('all');
  /** Click GD sao kê → mở explain card theo rowIndex. */
  const [explainRowIndex, setExplainRowIndex] = useState<number | null>(null);
  /** Click lô chưa map → mở slide-out chi tiết lô đó. */
  const [explainBatchRef, setExplainBatchRef] = useState<string | null>(null);

  const bgroups = useMemo((): BRecGroup[] => {
    const map = new Map<string, BRecGroup>();
    for (const d of batches) {
      for (const l of d.lines) {
        if (!l.batchRef) continue;
        const key = l.batchRef;
        if (!map.has(key)) {
          map.set(key, {
            batchRef: key,
            sheetDate: l.sheetDate,
            fileName: d.file.name,
            lineCount: 0,
            totalAmount: 0,
            lines: [],
          });
        }
        const g = map.get(key)!;
        g.lineCount += 1;
        g.totalAmount += l.amount;
        g.lines.push(l);
      }
    }
    return [...map.values()].sort((a, b) => (a.sheetDate ?? '').localeCompare(b.sheetDate ?? ''));
  }, [batches]);

  const bgroupByRef = useMemo(() => {
    const m = new Map<string, BRecGroup>();
    for (const g of bgroups) m.set(g.batchRef, g);
    return m;
  }, [bgroups]);

  /** Auto-map: mỗi batchRef → 1 dòng sao kê (từ description). 1 GD có thể cover nhiều ref. */
  const autoMap = useMemo(() => {
    const m = new Map<string, BankStatementImportRow>();
    for (const row of saoke) {
      if ((row.debitAmount ?? 0) <= 0) continue;
      const refs = extractBulkRefsFromDescription(row.description);
      for (const ref of refs) {
        const norm = normalizeBulkRef(ref);
        // Match batch groups by normalized or raw ref
        for (const g of bgroups) {
          if (normalizeBulkRef(g.batchRef) === norm || g.batchRef === ref) {
            if (!m.has(g.batchRef)) m.set(g.batchRef, row);
          }
        }
      }
    }
    return m;
  }, [saoke, bgroups]);

  /** Resolve mapped sao kê row for a batchRef (manual ưu tiên). */
  const resolveMappedRow = useCallback((batchRef: string): BankStatementImportRow | undefined => {
    const manualIdx = manualMap[batchRef];
    if (manualIdx !== undefined) return saoke.find(r => r.rowIndex === manualIdx);
    if (suppressedAuto[batchRef]) return undefined;
    return autoMap.get(batchRef);
  }, [manualMap, suppressedAuto, saoke, autoMap]);

  /** Tất cả batchRef gắn với 1 GD (manual + auto). */
  const batchesForRow = useCallback((rowIndex: number): BRecGroup[] => {
    const refs = new Set<string>();
    for (const [ref, idx] of Object.entries(manualMap)) {
      if (idx === rowIndex) refs.add(ref);
    }
    for (const [ref, row] of autoMap) {
      if (row.rowIndex === rowIndex && manualMap[ref] === undefined && !suppressedAuto[ref]) {
        refs.add(ref);
      }
    }
    return [...refs].map(r => bgroupByRef.get(r)).filter((g): g is BRecGroup => !!g);
  }, [manualMap, autoMap, suppressedAuto, bgroupByRef]);

  /** Tổng tiền lô gắn với 1 GD. */
  const linkedBatchTotal = useCallback((rowIndex: number): number => {
    return batchesForRow(rowIndex).reduce((s, g) => s + g.totalAmount, 0);
  }, [batchesForRow]);

  const mapped = useMemo(
    () => bgroups.filter(g => !!resolveMappedRow(g.batchRef)),
    [bgroups, resolveMappedRow],
  );

  /** Lệch tiền theo tổng các lô gắn cùng 1 GD (không so từng lô đơn). */
  const mismatched = useMemo(() => {
    const seen = new Set<number>();
    const out: BRecGroup[] = [];
    for (const g of mapped) {
      const row = resolveMappedRow(g.batchRef);
      if (!row || seen.has(row.rowIndex)) continue;
      seen.add(row.rowIndex);
      const total = linkedBatchTotal(row.rowIndex);
      if (Math.abs((row.debitAmount ?? 0) - total) > 1) {
        // Đưa tất cả batch thuộc GD lệch vào filter
        out.push(...batchesForRow(row.rowIndex));
      }
    }
    return out;
  }, [mapped, resolveMappedRow, linkedBatchTotal, batchesForRow]);

  const filteredGroups = useMemo(() => {
    if (filterMode === 'mapped') return mapped;
    if (filterMode === 'mismatched') return mismatched;
    if (filterMode === 'unmapped') {
      const mappedRefs = new Set(mapped.map(g => g.batchRef));
      return bgroups.filter(g => !mappedRefs.has(g.batchRef));
    }
    return bgroups;
  }, [filterMode, bgroups, mapped, mismatched]);

  const lookupRows = useMemo(() => {
    const q = searchTerm.trim().toLowerCase();
    return saoke
      .filter(r => (r.debitAmount ?? 0) > 0)
      .filter(r => !q
        || (r.description ?? '').toLowerCase().includes(q)
        || String(r.debitAmount ?? '').includes(q)
        || (r.referenceCode ?? '').toLowerCase().includes(q),
      )
      .sort((a, b) => (b.debitAmount ?? 0) - (a.debitAmount ?? 0))
      .slice(0, 40);
  }, [saoke, searchTerm]);

  const assignBatchToRow = useCallback((batchRef: string, rowIndex: number) => {
    setManualMap(prev => ({ ...prev, [batchRef]: rowIndex }));
    setSuppressedAuto(prev => {
      if (!prev[batchRef]) return prev;
      const n = { ...prev };
      delete n[batchRef];
      return n;
    });
    setLookupOpen(null);
    setExplainBatchRef(null);
    setExplainRowIndex(rowIndex);
  }, []);

  const closeExplain = useCallback(() => {
    setExplainRowIndex(null);
    setExplainBatchRef(null);
  }, []);

  const openMappedExplain = useCallback((rowIndex: number) => {
    setExplainBatchRef(null);
    setExplainRowIndex(prev => (prev === rowIndex ? null : rowIndex));
  }, []);

  const openUnmappedBatchExplain = useCallback((batchRef: string) => {
    setExplainRowIndex(null);
    setExplainBatchRef(prev => (prev === batchRef ? null : batchRef));
  }, []);

  const clearBatchMap = useCallback((batchRef: string) => {
    setManualMap(prev => {
      if (prev[batchRef] === undefined) return prev;
      const n = { ...prev };
      delete n[batchRef];
      return n;
    });
    setSuppressedAuto(prev => ({ ...prev, [batchRef]: true }));
  }, []);

  if (batches.length === 0 || saoke.length === 0) {
    return (
      <div className={styles.reconcileEmpty}>
        Cần có cả file <strong>sao kê</strong> và file <strong>thanh toán lô</strong> để đối soát tự động
      </div>
    );
  }

  if (bgroups.length === 0) {
    return (
      <div className={styles.reconcileEmpty}>
        Không phát hiện lệnh CK lô nào trong file thanh toán lô (thiếu trường Ref No trong header?)
      </div>
    );
  }

  const explainRow = explainRowIndex != null ? saoke.find(r => r.rowIndex === explainRowIndex) : undefined;
  const explainBatches = explainRowIndex != null
    ? batchesForRow(explainRowIndex)
    : explainBatchRef
      ? ([bgroupByRef.get(explainBatchRef)].filter((g): g is BRecGroup => !!g))
      : [];
  const explainBatchSum = explainBatches.reduce((s, g) => s + g.totalAmount, 0);
  const explainVariance = (explainRow?.debitAmount ?? 0) - explainBatchSum;
  const showExplain = !!explainRow || !!explainBatchRef;

  const batchPreviewText = (g: BRecGroup): string => {
    const parts = g.lines
      .slice(0, 3)
      .map(l => {
        const who = (l.beneficiaryName || '').trim();
        const desc = (l.description || '').trim();
        if (who && desc) return `${who}: ${desc}`;
        return who || desc || '';
      })
      .filter(Boolean);
    if (parts.length === 0) return '— không có nội dung chi tiết —';
    const more = g.lines.length > 3 ? ` … (+${g.lines.length - 3})` : '';
    return parts.join(' · ') + more;
  };

  return (
    <div className={styles.reconcilePanel}>
      {/* Summary stats — click to filter */}
      <div className={styles.reconcileStats}>
        <button
          className={`${styles.reconcileStat} ${filterMode === 'all' ? styles.reconcileStatActive : ''}`}
          onClick={() => setFilterMode('all')}
        >
          <span className={styles.reconcileStatVal}>{bgroups.length}</span> tất cả
        </button>
        <button
          className={`${styles.reconcileStat} ${styles.reconcileStatOk} ${filterMode === 'mapped' ? styles.reconcileStatActive : ''}`}
          onClick={() => setFilterMode(prev => (prev === 'mapped' ? 'all' : 'mapped'))}
        >
          <span className={styles.reconcileStatVal}>{mapped.length}</span> đã map
        </button>
        <button
          className={`${styles.reconcileStat} ${mismatched.length > 0 ? styles.reconcileStatErr : styles.reconcileStatOk} ${filterMode === 'mismatched' ? styles.reconcileStatActive : ''}`}
          onClick={() => setFilterMode(prev => (prev === 'mismatched' ? 'all' : 'mismatched'))}
        >
          <span className={styles.reconcileStatVal}>{mismatched.length}</span> lệch tiền
        </button>
        <button
          className={`${styles.reconcileStat} ${bgroups.length - mapped.length > 0 ? styles.reconcileStatWarn : styles.reconcileStatOk} ${filterMode === 'unmapped' ? styles.reconcileStatActive : ''}`}
          onClick={() => setFilterMode(prev => (prev === 'unmapped' ? 'all' : 'unmapped'))}
        >
          <span className={styles.reconcileStatVal}>{bgroups.length - mapped.length}</span> chưa map
        </button>
        {filterMode !== 'all' && (
          <button className={`${styles.reconcileStat} ${styles.reconcileStatClear}`} onClick={() => setFilterMode('all')}>
            ✕ Bỏ lọc
          </button>
        )}
      </div>

      {/* Explain slide-out — mapped GD hoặc lô chưa map */}
      {showExplain && (
        <div className={styles.explainOverlay} onClick={closeExplain}>
          <aside
            className={styles.explainSlideout}
            onClick={e => e.stopPropagation()}
            role="dialog"
            aria-label="Giải thích giao dịch"
          >
            <div className={styles.explainCardHeader}>
              <div className={styles.explainCardTitle}>
                <span className={styles.explainCardBadge}>
                  {explainRow ? 'Giải thích GD' : 'Chi tiết lô (chưa map)'}
                </span>
                {explainRow ? (
                  <>
                    <span className={styles.explainCardDate}>{explainRow.transactionDate ?? '—'}</span>
                    <span className={styles.explainCardAmt}>{formatAmount(explainRow.debitAmount)}</span>
                  </>
                ) : explainBatches[0] ? (
                  <>
                    <span className={styles.explainCardDate}>{explainBatches[0].sheetDate ?? '—'}</span>
                    <span className={styles.explainCardAmt}>{formatAmount(explainBatches[0].totalAmount)}</span>
                  </>
                ) : null}
              </div>
              <button className={styles.explainCardClose} onClick={closeExplain} title="Đóng">
                ✕
              </button>
            </div>

            <div className={styles.explainSlideBody}>
              {explainRow ? (
                <>
                  <div className={styles.explainCardDesc}>{explainRow.description ?? '—'}</div>
                  {explainRow.referenceCode && (
                    <div className={styles.explainCardRef}>Ref: {explainRow.referenceCode}</div>
                  )}
                  <div className={styles.explainCardStats}>
                    <span><strong>{explainBatches.length}</strong> lô gắn</span>
                    <span>Tổng lô: <strong>{formatAmount(explainBatchSum)}</strong></span>
                    <span style={{ color: Math.abs(explainVariance) < 1 ? '#15803d' : '#dc2626', fontWeight: 700 }}>
                      {Math.abs(explainVariance) < 1 ? '✓ Khớp' : `Lệch ${explainVariance > 0 ? '+' : ''}${formatAmount(explainVariance)}`}
                    </span>
                  </div>
                </>
              ) : (
                <div className={styles.explainCardStats}>
                  <span className={styles.reconcileUnmapped}>Chưa gắn GD sao kê</span>
                  <span><strong>{explainBatches[0]?.lineCount ?? 0}</strong> dòng chi tiết</span>
                  {explainBatches[0] && (
                    <span className={styles.reconcileBatchRef}>{explainBatches[0].batchRef}</span>
                  )}
                </div>
              )}

              {explainBatches.length === 0 ? (
                <div className={styles.reconcileEmpty}>Chưa gắn lô nào — dùng «+ Chọn» trên dòng lô để gán GD này</div>
              ) : (
                <div className={styles.explainBatchList}>
                  {explainBatches.map(g => (
                    <div key={g.batchRef} className={styles.explainBatchBlock}>
                      <div className={styles.explainBatchHead}>
                        <span className={styles.reconcileBatchRef}>{g.batchRef}</span>
                        <span className={styles.explainBatchMeta}>
                          {g.sheetDate ?? '—'} · {g.lineCount} GD · {formatAmount(g.totalAmount)}
                        </span>
                        <span className={styles.reconcileFile}>{g.fileName.replace(/\.[^.]+$/, '')}</span>
                        {explainRow && (
                          <button
                            className={`${styles.reconcileLookupBtn} ${styles.reconcileLookupBtnGray}`}
                            title="Bỏ gắn lô này"
                            onClick={() => clearBatchMap(g.batchRef)}
                          >
                            Bỏ gắn
                          </button>
                        )}
                      </div>
                      <div className={styles.explainDetailWrap}>
                        <table className={styles.explainDetailTable}>
                          <thead>
                            <tr>
                              <th>#</th>
                              <th>Người nhận</th>
                              <th>Ngân hàng</th>
                              <th>STK</th>
                              <th className={styles.reconcileThR}>Số tiền</th>
                              <th>Nội dung</th>
                              <th>TT</th>
                            </tr>
                          </thead>
                          <tbody>
                            {g.lines.map((l, i) => (
                              <tr key={`${g.batchRef}-${l.lineIndex}-${i}`}>
                                <td>{l.lineIndex || i + 1}</td>
                                <td>{l.beneficiaryName || '—'}</td>
                                <td title={l.bankName}>{l.bankName || '—'}</td>
                                <td>{l.accountNumber || '—'}</td>
                                <td className={styles.reconcileThR}>{formatAmount(l.amount)}</td>
                                <td>{l.description || '—'}</td>
                                <td>{l.status || '—'}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </aside>
        </div>
      )}

      {/* Reconciliation table */}
      <div className={styles.reconcileTableWrap}>
        <table className={styles.reconcileTable}>
          <thead>
            <tr>
              <th className={styles.reconcileTh}>#</th>
              <th className={styles.reconcileTh}>Mã lô</th>
              <th className={styles.reconcileTh}>Ngày</th>
              <th className={`${styles.reconcileTh} ${styles.reconcileThR}`}>Tiền lô</th>
              <th className={`${styles.reconcileTh} ${styles.reconcileThC}`}># GD</th>
              <th className={styles.reconcileTh}>Nội dung GD / sao kê — click để xem</th>
              <th className={`${styles.reconcileTh} ${styles.reconcileThR}`}>Tiền SK</th>
              <th className={`${styles.reconcileTh} ${styles.reconcileThR}`}>Chênh (tổng lô)</th>
              <th className={styles.reconcileTh}></th>
            </tr>
          </thead>
          <tbody>
            {filteredGroups.length === 0 ? (
              <tr>
                <td colSpan={9} className={styles.reconcileEmpty}>Không có dòng phù hợp với bộ lọc</td>
              </tr>
            ) : filteredGroups.map((g, idx) => {
              const mappedRow = resolveMappedRow(g.batchRef);
              const isManual = manualMap[g.batchRef] !== undefined;
              const linkedCount = mappedRow ? batchesForRow(mappedRow.rowIndex).length : 0;
              const batchSum = mappedRow ? linkedBatchTotal(mappedRow.rowIndex) : 0;
              const saokeAmt = mappedRow?.debitAmount ?? 0;
              const variance = saokeAmt - batchSum;
              const isMismatch = !!mappedRow && Math.abs(variance) > 1;
              const isOpen = lookupOpen === g.batchRef;
              const isExplaining = mappedRow
                ? explainRowIndex === mappedRow.rowIndex
                : explainBatchRef === g.batchRef;
              const rowCls = [
                styles.reconcileTr,
                isMismatch ? styles.reconcileTrMismatch : mappedRow ? styles.reconcileTrOk : styles.reconcileTrMissing,
                isExplaining ? styles.reconcileTrExplain : '',
              ].join(' ');

              return (
                <React.Fragment key={g.batchRef}>
                  <tr className={rowCls}>
                    <td className={styles.reconcileTd}>{idx + 1}</td>
                    <td className={styles.reconcileTd}>
                      <span className={styles.reconcileBatchRef}>{g.batchRef}</span>
                      <span className={styles.reconcileFile}>{g.fileName.replace(/\.[^.]+$/, '')}</span>
                    </td>
                    <td className={`${styles.reconcileTd} ${styles.reconcileTdDate}`}>
                      {g.sheetDate?.split('/').slice(0, 2).join('/') ?? '—'}
                    </td>
                    <td className={`${styles.reconcileTd} ${styles.reconcileTdAmtBatch}`}>
                      {formatAmount(g.totalAmount)}
                    </td>
                    <td className={`${styles.reconcileTd} ${styles.reconcileThC}`}>{g.lineCount}</td>
                    <td className={styles.reconcileTd}>
                      {mappedRow ? (
                        <button
                          type="button"
                          className={styles.reconcileGdBtn}
                          onClick={() => openMappedExplain(mappedRow.rowIndex)}
                          title="Xem giải thích — các lô gắn với GD này"
                        >
                          <div className={styles.reconcileRowDesc}>{mappedRow.description ?? '—'}</div>
                          <div className={styles.reconcileRowMeta}>
                            {mappedRow.transactionDate}
                            {' · '}
                            {isManual ? '✏ Manual' : '✓ Auto'}
                            {linkedCount > 1 ? ` · ${linkedCount} lô` : ''}
                            {isExplaining ? ' · đang xem' : ''}
                          </div>
                        </button>
                      ) : (
                        <button
                          type="button"
                          className={styles.reconcileGdBtn}
                          onClick={() => openUnmappedBatchExplain(g.batchRef)}
                          title="Xem chi tiết nội dung giao dịch lô"
                        >
                          <div className={styles.reconcileRowDesc}>{batchPreviewText(g)}</div>
                          <div className={styles.reconcileRowMeta}>
                            <span className={styles.reconcileUnmapped}>chưa map</span>
                            {` · ${g.lineCount} dòng`}
                            {isExplaining ? ' · đang xem' : ' · click xem chi tiết'}
                          </div>
                        </button>
                      )}
                    </td>
                    <td className={`${styles.reconcileTd} ${styles.reconcileThR}`} style={{ color: saokeAmt > 0 ? '#111' : '#9ca3af' }}>
                      {saokeAmt > 0 ? formatAmount(saokeAmt) : '—'}
                    </td>
                    <td className={`${styles.reconcileTd} ${styles.reconcileThR}`}>
                      {mappedRow ? (
                        <span style={{ fontWeight: 700, color: Math.abs(variance) < 1 ? '#15803d' : variance > 0 ? '#b45309' : '#dc2626' }}>
                          {Math.abs(variance) < 1
                            ? '✓ Khớp'
                            : `${variance > 0 ? '+' : ''}${formatAmount(variance)}`}
                          {linkedCount > 1 && (
                            <span className={styles.reconcileMultiHint}> / {linkedCount} lô</span>
                          )}
                        </span>
                      ) : '—'}
                    </td>
                    <td className={`${styles.reconcileTd} ${styles.reconcileActions}`}>
                      <button
                        className={styles.reconcileLookupBtn}
                        onClick={() => {
                          setLookupOpen(prev => (prev === g.batchRef ? null : g.batchRef));
                          setSearchTerm('');
                        }}
                      >
                        {isOpen ? '✕ Đóng' : mappedRow ? 'Đổi / +lô' : '+ Chọn'}
                      </button>
                      {mappedRow && (
                        <button
                          className={`${styles.reconcileLookupBtn} ${styles.reconcileLookupBtnGray}`}
                          title="Bỏ map lô này (GD vẫn giữ các lô khác)"
                          onClick={() => clearBatchMap(g.batchRef)}
                        >
                          ✕
                        </button>
                      )}
                    </td>
                  </tr>

                  {isOpen && (
                    <tr>
                      <td colSpan={9} className={styles.reconcileLookupCell}>
                        <div className={styles.reconcileLookupPanel}>
                          <div className={styles.reconcileLookupHint}>
                            Gắn lô <code>{g.batchRef}</code> ({formatAmount(g.totalAmount)}) vào 1 GD sao kê.
                            {' '}Cùng 1 GD có thể gắn nhiều lô — chọn lại GD đã dùng sẽ thêm lô này vào.
                          </div>
                          <input
                            className={styles.reconcileLookupInput}
                            autoFocus
                            placeholder="Tìm nội dung, số tiền hoặc mã tham chiếu sao kê..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                          />
                          {lookupRows.length === 0 ? (
                            <div className={styles.reconcileLookupEmpty}>Không tìm thấy giao dịch chi phù hợp</div>
                          ) : (
                            <div className={styles.reconcileLookupList}>
                              {lookupRows.map(r => {
                                const already = batchesForRow(r.rowIndex);
                                const afterSum = already
                                  .filter(x => x.batchRef !== g.batchRef)
                                  .reduce((s, x) => s + x.totalAmount, 0) + g.totalAmount;
                                const vDiff = (r.debitAmount ?? 0) - afterSum;
                                const isClose = Math.abs(vDiff) < 1000;
                                const alreadyLinked = already.some(x => x.batchRef === g.batchRef);
                                return (
                                  <button
                                    key={r.rowIndex}
                                    className={`${styles.reconcileLookupItem} ${isClose ? styles.reconcileLookupItemClose : ''}`}
                                    onClick={() => assignBatchToRow(g.batchRef, r.rowIndex)}
                                  >
                                    <span className={styles.reconcileLookupItemDate}>{r.transactionDate ?? '—'}</span>
                                    <span
                                      className={styles.reconcileLookupItemAmt}
                                      style={{ color: Math.abs(vDiff) < 1 ? '#15803d' : '#b91c1c' }}
                                    >
                                      {formatAmount(r.debitAmount)}
                                    </span>
                                    <span className={styles.reconcileLookupItemDesc}>
                                      {r.description ?? '—'}
                                      {already.length > 0 && (
                                        <span className={styles.reconcileMultiHint}>
                                          {' '}({alreadyLinked ? 'đã gắn lô này' : `đã có ${already.length} lô`}
                                          {` → tổng sau: ${formatAmount(afterSum)}`})
                                        </span>
                                      )}
                                    </span>
                                    <span className={styles.reconcileLookupItemRef}>{r.referenceCode ?? ''}</span>
                                  </button>
                                );
                              })}
                            </div>
                          )}
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

// ── Component ─────────────────────────────────────────────────────────────────

const Step1Upload: React.FC<Step1UploadProps> = ({
  bankStatements,
  batchPayments,
  skipEmptyRows,
  onSkipEmptyRowsChange,
  onBankStatementSelect,
  onBankStatementRemove,
  onBatchPaymentAdd,
  onBatchPaymentRemove,
  onSmartFolderImport,
  onNext,
  parseProgress,
  partialRows,
  bulkDetectedFiles = [],
  onBulkConfirm,
  onBulkReject,
  parsedBatchPaymentDetails = [],
}) => {
  const [readingFolder, setReadingFolder] = useState(false);
  const [readingBatchFolder, setReadingBatchFolder] = useState(false);
  const [conflicts, setConflicts] = useState<ConflictItem[]>([]);
  /** Files không conflict — sẽ add ngay sau khi user resolve conflicts. */
  const [pendingNew, setPendingNew] = useState<File[]>([]);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchFolderInputRef = useRef<HTMLInputElement>(null);

  const isParsing = !!parseProgress;
  const hasConflict = conflicts.length > 0;
  const allConflictsResolved = conflicts.length > 0 && conflicts.every(c => c.resolution !== undefined);

  // ── Core: phân tích file mới — tách conflict vs. clean ──────────────────────

  const processSelectedFiles = useCallback((newFiles: File[]) => {
    const supported = filterSupportedFiles(newFiles);
    if (supported.length === 0) return;

    const existingNames = bankStatements.map(bs => bs.file.name);
    const conflictItems: ConflictItem[] = [];
    const cleanFiles: File[] = [];

    for (const f of supported) {
      const existingIdx = existingNames.indexOf(f.name);
      if (existingIdx !== -1) {
        conflictItems.push({
          file: f,
          existingIndex: existingIdx,
          existingName: f.name,
          resolution: undefined,
        });
      } else {
        cleanFiles.push(f);
      }
    }

    if (conflictItems.length > 0) {
      setConflicts(conflictItems);
      setPendingNew(cleanFiles);
    } else {
      // Không có conflict — add ngay
      onBankStatementSelect(cleanFiles);
    }
  }, [bankStatements, onBankStatementSelect]);

  // ── File input (files + folder) ──────────────────────────────────────────────

  const handleFileInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      processSelectedFiles(Array.from(e.target.files));
    }
    // Reset để có thể chọn lại cùng file
    e.target.value = '';
  }, [processSelectedFiles]);

  const handleFolderInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      // Folder input → smart detect + route tự động (không show confirm panel)
      onSmartFolderImport(Array.from(e.target.files));
    }
    e.target.value = '';
  }, [onSmartFolderImport]);

  const handleBatchFileInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onBatchPaymentAdd(filterSupportedFiles(Array.from(e.target.files)));
    }
    e.target.value = '';
  }, [onBatchPaymentAdd]);

  const handleBatchFolderInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      // Batch zone folder → cũng dùng smart detect (tránh sao kê lọt vào batch)
      onSmartFolderImport(Array.from(e.target.files));
    }
    e.target.value = '';
  }, [onSmartFolderImport]);

  // ── Drag & Drop — hỗ trợ cả file lẫn folder ────────────────────────────────

  const handleBsDrop = useCallback(async (e: React.DragEvent) => {
    e.preventDefault();
    if (isParsing) return;

    const items = Array.from(e.dataTransfer.items);
    const hasEntry = items.some(item => typeof item.webkitGetAsEntry === 'function');

    if (hasEntry) {
      const entries = items
        .map(item => item.webkitGetAsEntry())
        .filter((entry): entry is FileSystemEntry => entry !== null);
      const hasFolder = entries.some(e => e.isDirectory);

      if (hasFolder) {
        // Folder drop → smart detect + route tự động
        setReadingFolder(true);
        try {
          const allFiles = (await Promise.all(entries.map(readFilesFromEntry))).flat();
          onSmartFolderImport(allFiles);
        } finally {
          setReadingFolder(false);
        }
      } else {
        // File drop (không phải folder) → xử lý bình thường với conflict check
        setReadingFolder(true);
        try {
          const allFiles = (await Promise.all(entries.map(readFilesFromEntry))).flat();
          processSelectedFiles(allFiles);
        } finally {
          setReadingFolder(false);
        }
      }
    } else {
      // Fallback: dùng files trực tiếp
      processSelectedFiles(Array.from(e.dataTransfer.files));
    }
  }, [isParsing, processSelectedFiles, onSmartFolderImport]);

  const handleBatchDrop = useCallback(async (e: React.DragEvent) => {
    e.preventDefault();
    if (readingBatchFolder) return;

    const items = Array.from(e.dataTransfer.items);
    const hasEntry = items.some(item => typeof item.webkitGetAsEntry === 'function');

    if (hasEntry) {
      const entries = items
        .map(item => item.webkitGetAsEntry())
        .filter((entry): entry is FileSystemEntry => entry !== null);
      const hasFolder = entries.some(e => e.isDirectory);

      if (hasFolder) {
        // Folder drop trên batch zone → smart detect (tránh sao kê lọt vào batch)
        setReadingBatchFolder(true);
        try {
          const allFiles = (await Promise.all(entries.map(readFilesFromEntry))).flat();
          onSmartFolderImport(allFiles);
        } finally {
          setReadingBatchFolder(false);
        }
      } else {
        // File drop thường → add trực tiếp vào batch
        setReadingBatchFolder(true);
        try {
          const allFiles = (await Promise.all(entries.map(readFilesFromEntry))).flat();
          onBatchPaymentAdd(filterSupportedFiles(allFiles));
        } finally {
          setReadingBatchFolder(false);
        }
      }
    } else {
      onBatchPaymentAdd(filterSupportedFiles(Array.from(e.dataTransfer.files)));
    }
  }, [readingBatchFolder, onBatchPaymentAdd, onSmartFolderImport]);

  // ── Conflict resolution ──────────────────────────────────────────────────────

  const setConflictResolution = useCallback((idx: number, resolution: 'skip' | 'override') => {
    setConflicts(prev => prev.map((c, i) => i === idx ? { ...c, resolution } : c));
  }, []);

  const handleSetAllConflicts = useCallback((resolution: 'skip' | 'override') => {
    setConflicts(prev => prev.map(c => ({ ...c, resolution })));
  }, []);

  const handleConfirmConflicts = useCallback(() => {
    const overrideItems = conflicts.filter(c => c.resolution === 'override');
    const overrideIndices = overrideItems.map(c => c.existingIndex).sort((a, b) => b - a); // desc để xoá đúng index
    const overrideFiles = overrideItems.map(c => c.file);

    const finalFiles = [...pendingNew, ...overrideFiles];

    if (finalFiles.length > 0) {
      onBankStatementSelect(finalFiles, overrideIndices);
    }
    setConflicts([]);
    setPendingNew([]);
  }, [conflicts, pendingNew, onBankStatementSelect]);

  const handleCancelConflicts = useCallback(() => {
    if (pendingNew.length > 0) onBankStatementSelect(pendingNew);
    setConflicts([]);
    setPendingNew([]);
  }, [pendingNew, onBankStatementSelect]);

  // ── IntersectionObserver + stat effects are now inside TxPanel ───────────────

  /** Tab ngoài: Sao kê (thu/chi) vs. Thanh toán lô vs. Đối soát. */
  const [outerTab, setOuterTab] = useState<'saoke' | 'batch' | 'reconcile'>('saoke');
  /** Sub-tab trong Sao kê: Thu tiền / Chi tiền. */
  const [saokeTab, setSaokeTab] = useState<'thu' | 'chi'>('thu');

  // ── Derived state ─────────────────────────────────────────────────────────────

  const canProceed = !isParsing && !hasConflict && !readingFolder
    && bankStatements.length > 0
    && bankStatements.some(bs => bs.rows.length > 0);

  /** Tất cả rows — dùng partialRows khi đang parse, bankStatements khi xong. */
  const allRows = useMemo(() => {
    const parsed = bankStatements.flatMap(bs => bs.rows);
    if (parsed.length > 0) return parsed;
    return partialRows ?? [];
  }, [bankStatements, partialRows]);

  /** Thu tiền: creditAmount > 0 hoặc suggestedVoucherType === 'bao_co'. */
  const thuRows = useMemo(
    () => allRows.filter(r => (r.creditAmount ?? 0) > 0 || r.suggestedVoucherType === 'bao_co'),
    [allRows],
  );

  /** Chi tiền: debitAmount > 0 hoặc suggestedVoucherType === 'bao_no'. */
  const chiRows = useMemo(
    () => allRows.filter(r => (r.debitAmount ?? 0) > 0 || r.suggestedVoucherType === 'bao_no'),
    [allRows],
  );

  const totalRows = bankStatements.reduce((s, bs) => s + bs.rows.length, 0);
  const displayRowCount = allRows.length;

  // ── Render ────────────────────────────────────────────────────────────────────

  return (
    <div className={styles.pageLayout}>

      {/* ════════ SIDEBAR TRÁI — steps + upload controls ════════ */}
      <aside className={styles.sidebar}>
        <div className={styles.sidebarHeader}>
          <h2 className={styles.title}>Bước 1</h2>
          <p className={styles.subtitle}>Chọn file sao kê (.xlsx / .xls / .csv)</p>

          {/* ── Next button — ngay dưới step title ── */}
          <button className={styles.nextButton} disabled={!canProceed} onClick={onNext} style={{ marginTop: 10, width: '100%' }}>
            {readingFolder
              ? 'Đang quét thư mục…'
              : isParsing
                ? `Đọc file… ${displayRowCount.toLocaleString('vi-VN')} dòng`
                : hasConflict
                  ? `⚠️ Giải quyết ${conflicts.length} file trùng`
                  : canProceed
                    ? `Tiếp theo → (${totalRows.toLocaleString('vi-VN')} dòng)`
                    : bankStatements.length === 0
                      ? 'Vui lòng chọn file sao kê'
                      : 'Không có dữ liệu hợp lệ'}
          </button>
        </div>

        {/* ── Drop zone sao kê ── */}
        <div className={styles.sideSection}>
          <div className={styles.sectionTitle}>📋 File sao kê ngân hàng</div>
          <div
            className={`${styles.dropZone} ${(bankStatements.length > 0 || isParsing || readingFolder) ? styles.dropZoneFilled : ''}`}
            onDragOver={e => e.preventDefault()}
            onDrop={!isParsing ? handleBsDrop : undefined}
          >
          {readingFolder && (
            <div className={styles.scanningWrap}>
              <span className={styles.scanSpinner}>📂</span>
              <span>Đang quét thư mục…</span>
            </div>
          )}
          {!readingFolder && bankStatements.length > 0 && (
            <div className={styles.batchFileList}>
              {bankStatements.map((bs: FileSlotInfo, i: number) => {
                const isValid = bs.rows.length > 0;
                return (
                  <div key={i} className={styles.batchFileItem}>
                    <span className={styles.batchFileName} title={bs.file.name}>{bs.file.name}</span>
                    {isValid
                      ? <span className={styles.validBadge}>✓ Hợp lệ</span>
                      : <span className={styles.invalidBadge}>✗ Không hợp lệ</span>
                    }
                    {isValid && <span className={styles.rowCountBadge}>{bs.rows.length.toLocaleString('vi-VN')} dòng</span>}
                    <button className={styles.batchFileRemove} onClick={() => onBankStatementRemove(i)} title="Xoá">✕</button>
                  </div>
                );
              })}
            </div>
          )}
          {!readingFolder && !isParsing && (
            <div className={styles.selectButtonRow}>
              <label className={styles.selectBtn}>
                <input type="file" accept=".xlsx,.xls,.csv" multiple hidden onChange={handleFileInput} />
                📄 Chọn file
              </label>
              <label className={styles.selectBtnFolder}>
                <input
                  type="file"
                  // eslint-disable-next-line react/no-unknown-property
                  {...({ webkitdirectory: '' } as React.InputHTMLAttributes<HTMLInputElement>)}
                  multiple hidden onChange={handleFolderInput} ref={folderInputRef}
                />
                📁 Thư mục
              </label>
            </div>
          )}
          {!readingFolder && bankStatements.length === 0 && !isParsing && (
            <div className={styles.dropPlaceholder}>
              <div className={styles.dropIcon}>📋</div>
              <div className={styles.dropHint}>Kéo thả file hoặc thư mục vào đây</div>
            </div>
          )}
        </div>
        </div>{/* end sideSection */}

        {/* ── Parse progress ── */}
        {parseProgress && (
          <div className={styles.parseProgressWrap}>
            <div className={styles.parseProgressLabel}>
              Đang đọc <strong>{parseProgress.fileName}</strong>…
              {parseProgress.total > 0 && (
                <> {parseProgress.loaded.toLocaleString('vi-VN')} / {parseProgress.total.toLocaleString('vi-VN')} dòng</>
              )}
            </div>
            <div className={styles.parseProgressBar}>
              <div
                className={styles.parseProgressFill}
                style={{
                  width: parseProgress.total > 0
                    ? `${Math.min(100, (parseProgress.loaded / parseProgress.total) * 100)}%`
                    : '60%',
                }}
              />
            </div>
          </div>
        )}

        {/* ── Conflict panel ── */}
        {hasConflict && (
          <div className={styles.conflictPanel}>
            <div className={styles.conflictPanelHeader}>
              <span className={styles.conflictIcon}>⚠️</span>
              <span className={styles.conflictTitle}>{conflicts.length} file trùng tên</span>
              <div className={styles.conflictBatchBtns}>
                <button className={styles.conflictBatchSkip} onClick={() => handleSetAllConflicts('skip')}>Bỏ qua tất cả</button>
                <button className={styles.conflictBatchOverride} onClick={() => handleSetAllConflicts('override')}>Ghi đè tất cả</button>
              </div>
            </div>
            <div className={styles.conflictList}>
              {conflicts.map((c, idx) => (
                <div key={idx} className={`${styles.conflictRow} ${c.resolution ? styles.conflictRowResolved : ''}`}>
                  <span className={styles.conflictFileIcon}>📄</span>
                  <span className={styles.conflictFileName} title={c.existingName}>{c.existingName}</span>
                  <div className={styles.conflictRowBtns}>
                    <button
                      className={`${styles.conflictRowBtn} ${c.resolution === 'skip' ? styles.conflictRowBtnActive : ''}`}
                      onClick={() => setConflictResolution(idx, 'skip')}
                    >
                      {c.resolution === 'skip' ? '✓ Bỏ qua' : 'Bỏ qua'}
                    </button>
                    <button
                      className={`${styles.conflictRowBtn} ${styles.conflictRowBtnOverride} ${c.resolution === 'override' ? styles.conflictRowBtnActive : ''}`}
                      onClick={() => setConflictResolution(idx, 'override')}
                    >
                      {c.resolution === 'override' ? '✓ Ghi đè' : 'Ghi đè'}
                    </button>
                  </div>
                </div>
              ))}
            </div>
            <div className={styles.conflictActions}>
              <button className={styles.conflictCancelBtn} onClick={handleCancelConflicts}>Huỷ</button>
              <button className={styles.conflictConfirmBtn} disabled={!allConflictsResolved} onClick={handleConfirmConflicts}>
                {allConflictsResolved
                  ? `Xác nhận (${conflicts.filter(c => c.resolution === 'override').length} ghi đè, ${conflicts.filter(c => c.resolution === 'skip').length} bỏ qua)`
                  : 'Chọn đủ để xác nhận'}
              </button>
            </div>
          </div>
        )}

        {/* ── Bulk payment confirm panel ── */}
        {bulkDetectedFiles.length > 0 && (
          <div className={styles.bulkConfirmPanel}>
            <div className={styles.bulkConfirmHeader}>
              <span className={styles.bulkConfirmIcon}>📦</span>
              <span className={styles.bulkConfirmTitle}>
                Phát hiện {bulkDetectedFiles.length} file thanh toán lô
              </span>
            </div>

            <p className={styles.bulkConfirmQuestion}>
              Các file có header <strong>"DANH SÁCH GIAO DỊCH"</strong> —
              chuyển sang mục <strong>File thanh toán lô</strong>?
            </p>

            {/* Per-file list với nút remove từng file */}
            <div className={styles.bulkConfirmList}>
              {bulkDetectedFiles.map((f, i) => (
                <div key={i} className={styles.bulkConfirmFile}>
                  <span className={styles.bulkConfirmFileIcon}>📄</span>
                  <span className={styles.bulkConfirmFileName} title={f.name}>{f.name}</span>
                  <button
                    className={styles.bulkRemoveOneBtn}
                    title="Bỏ qua file này"
                    onClick={() => {
                      // Lọc bỏ file này khỏi danh sách pending
                      const remaining = bulkDetectedFiles.filter((_, j) => j !== i);
                      if (remaining.length === 0) {
                        onBulkReject?.();
                      } else {
                        // Gọi reject rồi re-add remaining — hoặc dùng prop onBulkRemoveOne nếu có
                        // Workaround: reject all → confirm only remaining
                        onBulkReject?.();
                        setTimeout(() => onBulkConfirm?.(remaining), 0);
                      }
                    }}
                  >✕</button>
                </div>
              ))}
            </div>

            <div className={styles.bulkConfirmActions}>
              <button className={styles.bulkRejectBtn} onClick={onBulkReject}>
                Bỏ qua tất cả
              </button>
              <button
                className={styles.bulkMoveBtn}
                onClick={() => onBulkConfirm?.(bulkDetectedFiles)}
              >
                📦 Chuyển tất cả ({bulkDetectedFiles.length})
              </button>
            </div>
          </div>
        )}

        {/* ── Batch payment ── */}
        <div className={styles.sideSection}>
          <div className={styles.sectionTitle}>📄 File thanh toán lô</div>
          <div
            className={`${styles.dropZone} ${batchPayments.length > 0 ? styles.dropZoneFilled : ''}`}
            onDragOver={e => e.preventDefault()}
            onDrop={handleBatchDrop}
          >
            {readingBatchFolder && (
              <div className={styles.scanningWrap}>
                <span className={styles.scanSpinner}>📂</span>
                <span>Đang quét thư mục…</span>
              </div>
            )}

            {!readingBatchFolder && batchPayments.length > 0 && (
              <div className={styles.batchFileList}>
                {batchPayments.map((f, i) => (
                  <div key={i} className={styles.batchFileItem}>
                    <span className={styles.batchFileName} title={f.name}>📦 {f.name}</span>
                    <button className={styles.batchFileRemove} onClick={() => onBatchPaymentRemove(i)} title="Xoá">✕</button>
                  </div>
                ))}
              </div>
            )}

            {/* Buttons — luôn hiện khi không đang quét */}
            {!readingBatchFolder && (
              <div className={styles.selectButtonRow}>
                <label className={styles.selectBtn}>
                  <input type="file" accept=".xlsx,.xls,.csv" multiple hidden onChange={handleBatchFileInput} />
                  📄 Chọn file
                </label>
                <label className={styles.selectBtnFolder}>
                  <input
                    type="file"
                    // eslint-disable-next-line react/no-unknown-property
                    {...({ webkitdirectory: '' } as React.InputHTMLAttributes<HTMLInputElement>)}
                    multiple hidden onChange={handleBatchFolderInput} ref={batchFolderInputRef}
                  />
                  📁 Thư mục
                </label>
              </div>
            )}

            {!readingBatchFolder && batchPayments.length === 0 && (
              <div className={styles.dropPlaceholder}>
                <div className={styles.dropIcon}>📦</div>
                <div className={styles.dropHint}>Kéo thả file hoặc thư mục vào đây</div>
              </div>
            )}
          </div>
        </div>

        {/* ── Options ── */}
        <div className={styles.sideSection}>
          <div className={styles.checkboxRow}>
            <input type="checkbox" id="skip-empty-rows" checked={skipEmptyRows} onChange={e => onSkipEmptyRowsChange(e.target.checked)} />
            <label htmlFor="skip-empty-rows">Bỏ qua dòng trống (không có số tiền)</label>
          </div>
        </div>

      </aside>

      {/* ════════ CONTENT PHẢI — 2 outer tabs: Sao kê / Thanh toán lô ════════ */}
      <div className={styles.contentArea}>
        {displayRowCount === 0 && parsedBatchPaymentDetails.length === 0 && !isParsing ? (
          <div className={styles.contentEmpty}>
            <div className={styles.contentEmptyIcon}>📊</div>
            <div className={styles.contentEmptyText}>Chọn file sao kê để xem phân tích Thu / Chi</div>
          </div>
        ) : (
          <>
            {/* ── Outer tab bar ── */}
            <div className={styles.contentTabBar}>
              {/* Tab Sao kê */}
              <button
                className={`${styles.contentTab} ${outerTab === 'saoke' ? styles.contentTabActive : ''}`}
                onClick={() => setOuterTab('saoke')}
              >
                📋 Sao kê
                <span className={styles.contentTabCount}>
                  {isParsing ? displayRowCount.toLocaleString('vi-VN') : allRows.length.toLocaleString('vi-VN')}
                </span>
              </button>

              {/* Tab Thanh toán lô */}
              {parsedBatchPaymentDetails.length > 0 && (
                <button
                  className={`${styles.contentTab} ${outerTab === 'batch' ? styles.contentTabActive : ''}`}
                  onClick={() => setOuterTab('batch')}
                  style={outerTab === 'batch' ? { color: '#7c3aed', borderBottomColor: '#7c3aed' } : undefined}
                >
                  📦 Thanh toán lô
                  <span className={styles.contentTabCount}>
                    {parsedBatchPaymentDetails.reduce((s, d) => s + d.lines.length, 0).toLocaleString('vi-VN')}
                  </span>
                </button>
              )}

              {/* Tab Đối soát */}
              {parsedBatchPaymentDetails.length > 0 && allRows.length > 0 && (
                <button
                  className={`${styles.contentTab} ${outerTab === 'reconcile' ? styles.contentTabActive : ''}`}
                  onClick={() => setOuterTab('reconcile')}
                  style={outerTab === 'reconcile' ? { color: '#b45309', borderBottomColor: '#b45309' } : undefined}
                >
                  ⚖️ Đối soát
                </button>
              )}

              {isParsing && (
                <span className={styles.liveTagHeader}>● LIVE — {displayRowCount.toLocaleString('vi-VN')} dòng</span>
              )}
            </div>

            {/* ── Sao kê: sub-tab Thu / Chi ── */}
            {outerTab === 'saoke' && (
              <>
                {/* Sub-tab bar */}
                <div className={styles.saokeSubTabBar}>
                  <button
                    className={`${styles.saokeSubTab} ${saokeTab === 'thu' ? styles.saokeSubTabActive : ''}`}
                    onClick={() => setSaokeTab('thu')}
                  >
                    Thu tiền
                    <span className={styles.contentTabCount}>{thuRows.length.toLocaleString('vi-VN')}</span>
                  </button>
                  <button
                    className={`${styles.saokeSubTab} ${saokeTab === 'chi' ? styles.saokeSubTabActive : ''}`}
                    onClick={() => setSaokeTab('chi')}
                  >
                    Chi tiền
                    <span className={styles.contentTabCount}>{chiRows.length.toLocaleString('vi-VN')}</span>
                  </button>
                </div>

                {/* TxPanels — mount cả 2, ẩn/hiện bằng display để giữ state filter+scroll */}
                <div style={{ display: saokeTab === 'thu' ? 'flex' : 'none', flexDirection: 'column', flex: 1, minHeight: 0 }}>
                  <TxPanel title="Thu tiền" rows={thuRows} accentColor="#15803d" emptyText="Không có giao dịch thu tiền" isParsing={isParsing} />
                </div>
                <div style={{ display: saokeTab === 'chi' ? 'flex' : 'none', flexDirection: 'column', flex: 1, minHeight: 0 }}>
                  <TxPanel title="Chi tiền" rows={chiRows} accentColor="#b91c1c" emptyText="Không có giao dịch chi tiền" isParsing={isParsing} />
                </div>
              </>
            )}

            {/* ── Thanh toán lô ── */}
            {outerTab === 'batch' && (
              <BatchPanel details={parsedBatchPaymentDetails} />
            )}

            {/* ── Đối soát lệch tiền ── */}
            {outerTab === 'reconcile' && (
              <BatchReconcilePanel saoke={allRows} batches={parsedBatchPaymentDetails} />
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default Step1Upload;
