/**
 * Keyword nhận dạng file thanh toán lô — CHỈ dùng dạng KHÔNG DẤU + tiếng Anh.
 * Text từ Excel/CSV được normalize NFD + strip diacritics trước khi so sánh.
 */
const BULK_KEYWORDS_ND = [
  'danh sach giao dich',      // DANH SÁCH GIAO DỊCH
  'thanh toan theo lo',        // THANH TOÁN THEO LÔ
  'danh sach thanh toan',      // DANH SÁCH THANH TOÁN
  'list of bulk transaction',
  'bulk payment',
  'bulk transaction',
  'batch payment list',
];

/** Strip dấu + lowercase để so sánh nhất quán bất kể Unicode form (NFC/NFD). */
function normBulkText(s: string): string {
  return s
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')  // remove combining diacritics
    .replace(/[đĐ]/g, 'd')
    .toLowerCase();
}

/**
 * Phát hiện nhanh file thanh toán lô bằng cách quét 25 dòng đầu.
 * Chuẩn hoá text NFD + strip diacritics trước khi compare → không bị lỗi Unicode form.
 */
async function detectIsBulkPaymentFileQuick(file: File): Promise<boolean> {
  try {
    const buffer = await file.arrayBuffer();
    const isCsv = file.name.toLowerCase().endsWith('.csv');

    if (isCsv) {
      const raw = new TextDecoder('utf-8').decode(buffer).slice(0, 8000);
      const text = normBulkText(raw);
      return BULK_KEYWORDS_ND.some(kw => text.includes(kw));
    }

    // Excel — đọc 25 dòng đầu (sheetRows limit)
    const wb = XLSX.read(buffer, { type: 'array', sheetRows: 25 });
    const sheet = wb.Sheets[wb.SheetNames[0]];
    const rows = XLSX.utils.sheet_to_json<string[]>(sheet, { header: 1, defval: '' });

    for (const row of rows) {
      const text = normBulkText((row || []).join(' '));
      if (BULK_KEYWORDS_ND.some(kw => text.includes(kw))) return true;
    }

    return false;
  } catch {
    return false;
  }
}

/** Parse amount string từ Excel cell (hỗ trợ format VN: 1.234.567 hoặc 1234567). */
function parseBatchAmount(v: unknown): number {
  if (typeof v === 'number') return v;
  const s = String(v || '').trim().replace(/[^\d,.]/g, '');
  if (!s) return 0;
  // VN format: dấu chấm nghìn, dấu phẩy thập phân
  if (s.includes(',') && !s.includes('.')) return parseFloat(s.replace(/,/g, '')) || 0;
  if (s.includes('.') && s.split('.').length > 2) return parseFloat(s.replace(/\./g, '')) || 0;
  return parseFloat(s.replace(/,/g, '')) || 0;
}

/** Extract metadata từ header rows của sheet (Ref No + Ngày GD). */
function extractSheetMeta(rows: unknown[][]): { transactionDate?: string; refNumber?: string } {
  let transactionDate: string | undefined;
  let refNumber: string | undefined;
  for (let i = 0; i < Math.min(rows.length, 8); i++) {
    const cell = String((rows[i] as unknown[])?.[0] ?? '');
    const lower = cell.toLowerCase();
    // "Số tham chiếu (Ref No): 2610111212963637"
    if (lower.includes('ref no') || lower.includes('tham chi\u1ebfu')) {
      const m = cell.match(/:\s*(.+)$/);
      if (m) refNumber = m[1].trim();
    }
    // "Ngày giao dịch (Transaction date): 01/01/2026"
    if (lower.includes('transaction date') || lower.includes('ng\u00e0y giao d\u1ecbch')) {
      const m = cell.match(/:\s*(.+)$/);
      if (m) transactionDate = m[1].trim();
    }
  }
  return { transactionDate, refNumber };
}

/**
 * Parse 1 sheet (rawRows) lấy dòng batch.
 * Trả về [] nếu không nhận dạng được header.
 */
function parseBatchSheet(
  rawRows: unknown[][],
  meta: { transactionDate?: string; refNumber?: string },
  lineOffset = 0,
): BatchDetailLine[] {
  // Tìm header row (score cao nhất trong 30 dòng đầu)
  let headerRowIndex = -1;
  let bestScore = 0;
  for (let i = 0; i < Math.min(rawRows.length, 30); i++) {
    const rowText = (rawRows[i] as string[] || []).map(c => String(c)).join(' ').toLowerCase().replace(/\r?\n/g, ' ');
    let score = 0;
    if (rowText.includes('th\u1ee5 h\u01b0\u1edfng') || rowText.includes('beneficiary')) score += 3;
    if (rowText.includes('s\u1ed1 ti\u1ec1n') || rowText.includes('amount')) score += 2;
    if (rowText.includes('t\u00e0i kho\u1ea3n') || rowText.includes('account')) score += 2;
    if (rowText.includes('ng\u00e2n h\u00e0ng') || rowText.includes('bank')) score += 1;
    if (rowText.includes('chi ti\u1ebft') || rowText.includes('n\u1ed9i dung') || rowText.includes('payment')) score += 1;
    if (score > bestScore) { bestScore = score; headerRowIndex = i; }
  }
  if (headerRowIndex === -1 || bestScore < 4) return [];

  // Normalize headers: xử lý \r\n (MB dùng multiline header cell)
  const headers = (rawRows[headerRowIndex] as string[] || [])
    .map(h => String(h).trim().toLowerCase().replace(/\r?\n/g, ' '));

  const ci = (...kws: string[]) => {
    for (const kw of kws) {
      const idx = headers.findIndex(h => h.includes(kw));
      if (idx >= 0) return idx;
    }
    return -1;
  };

  // MB format: STT | Số TK | Tên đơn vị thụ hưởng | Ngân hàng | Số tiền | Chi tiết TT | Phí | Trạng thái | Mã FT | FM
  const accIdx   = ci('s\u1ed1 t\u00e0i kho\u1ea3n', 't\u00e0i kho\u1ea3n', 'account no', 'account', 'stk', 's\u1ed1 tk');
  const nameIdx  = ci('t\u00ean \u0111\u01a1n v\u1ecb th\u1ee5 h\u01b0\u1edfng', 'th\u1ee5 h\u01b0\u1edfng', 'beneficiary name', 'beneficiary', 't\u00ean');
  const bankIdx  = ci('ng\u00e2n h\u00e0ng th\u1ee5 h\u01b0\u1edfng', 'ng\u00e2n h\u00e0ng', 'beneficiary bank', 'bank');
  const amtIdx   = ci('s\u1ed1 ti\u1ec1n giao d\u1ecbch', 's\u1ed1 ti\u1ec1n', 'amount', 'ti\u1ec1n');
  const descIdx  = ci('chi ti\u1ebft thanh to\u00e1n', 'payment details', 'n\u1ed9i dung chuy\u1ec3n', 'n\u1ed9i dung', 'di\u1ec5n gi\u1ea3i', 'content');
  const statusIdx = ci('tr\u1ea1ng th\u00e1i', 'status', 'k\u1ebft qu\u1ea3');
  const ftIdx    = ci('m\u00e3 giao d\u1ecbch', 's\u1ed1 ft', 'ft number', 'ft2', 'transaction id');
  // Fallback FT: thường ở cột cuối có value bắt đầu "FT"
  const guessedFtIdx = ftIdx >= 0 ? ftIdx : headers.findIndex((_, ci2) => {
    const vals = (rawRows.slice(headerRowIndex + 1, headerRowIndex + 5) as string[][])
      .map(r => String(r?.[ci2] ?? ''));
    return vals.some(v => /^ft\d+/i.test(v));
  });

  const lines: BatchDetailLine[] = [];
  for (let i = headerRowIndex + 1; i < rawRows.length; i++) {
    const row = rawRows[i] as unknown[];
    if (!row || row.every(c => String(c).trim() === '')) continue;
    const name = nameIdx >= 0 ? String(row[nameIdx] ?? '').trim() : '';
    if (!name || /^t\u1ed5ng/i.test(name)) continue; // skip "Tổng" row

    const amount = amtIdx >= 0 ? parseBatchAmount(row[amtIdx]) : 0;
    const ftRaw = (guessedFtIdx >= 0 ? String(row[guessedFtIdx] ?? '') : '').trim();

    lines.push({
      lineIndex: lineOffset + (i - headerRowIndex - 1),
      beneficiaryName: name,
      accountNumber: accIdx >= 0 ? String(row[accIdx] ?? '').trim() || undefined : undefined,
      bankName:       bankIdx >= 0 ? String(row[bankIdx] ?? '').trim() || undefined : undefined,
      amount,
      description:    descIdx >= 0 ? String(row[descIdx] ?? '').trim() || undefined : undefined,
      status:         statusIdx >= 0 ? String(row[statusIdx] ?? '').trim() || undefined : undefined,
      ftNumber:       ftRaw || undefined,
      sheetDate:      meta.transactionDate,
      batchRef:       meta.refNumber,
    });
  }
  return lines;
}

/**
 * Parse file thanh toán lô (xlsx/xls/csv) — hỗ trợ MULTI-SHEET (MB format: mỗi ngày 1 sheet).
 * Trả về danh sách dòng phẳng; mỗi dòng có sheetDate + batchRef của lô tương ứng.
 */
async function parseBatchPaymentFileForDisplay(file: File): Promise<BatchDetailLine[]> {
  try {
    const buffer = await file.arrayBuffer();
    const allLines: BatchDetailLine[] = [];

    if (file.name.toLowerCase().endsWith('.csv')) {
      const text = new TextDecoder('utf-8').decode(buffer);
      const rawRows = text.split('\n').filter(Boolean).map(l =>
        l.split(/[,;\t]/).map(c => c.trim()),
      ) as unknown[][];
      const meta = extractSheetMeta(rawRows);
      allLines.push(...parseBatchSheet(rawRows, meta));
    } else {
      const wb = XLSX.read(buffer, { type: 'array' });
      let lineOffset = 0;
      for (const sheetName of wb.SheetNames) {
        const sheet = wb.Sheets[sheetName];
        const rawRows: unknown[][] = XLSX.utils.sheet_to_json<unknown[]>(sheet, { header: 1, defval: '' });
        const meta = extractSheetMeta(rawRows);
        const sheetLines = parseBatchSheet(rawRows, meta, lineOffset);
        allLines.push(...sheetLines);
        lineOffset += sheetLines.length;
      }
    }
    return allLines;
  } catch {
    return [];
  }
}

/** Trạng thái đọc file từng dòng (progressive parse). */
interface ParseProgress {
  fileName: string;
  /** Số dòng đã đọc xong. */
  loaded: number;
  /** Tổng số dòng hợp lệ trong file. */
  total: number;
}

const ImportSaoKePage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [step, setStep] = useState<ImportStep>(1);
  const [bankStatements, setBankStatements] = useState<FileSlotInfo[]>([]);
  const [batchPayments, setBatchPayments] = useState<File[]>([]);
  const [skipEmptyRows, setSkipEmptyRows] = useState(true);
  const [matchResult, setMatchResult] = useState<CustomerMatchResult | null>(null);
  const [dryRunResult, setDryRunResult] = useState<import('../../../services/kt/bankStatementImportModels').BankStatementDryRunResult | null>(null);
  const [customerResolutions, setCustomerResolutions] = useState<CustomerResolution[]>([]);
  const [importResult, setImportResult] = useState<import('../../../services/kt/bankStatementImportModels').BankStatementImportResult | null>(null);
  const [importProgress, setImportProgress] = useState<ImportProgress>({
    total: 0, done: 0, errors: [], running: false, finished: false, duplicateSkipped: 0,
  });
  const [loading, setLoading] = useState(false);
  const [batchDetailMap, setBatchDetailMap] = useState<Map<string, BatchDetailLine[]>>(new Map());
  /** Parse progress — hiển thị line-by-line khi load file. */
  const [parseProgress, setParseProgress] = useState<ParseProgress | null>(null);
  /** Các dòng đã parse được (partial), cập nhật từng chunk để hiển thị trực tiếp. */
  const [partialRows, setPartialRows] = useState<BankStatementImportRow[]>([]);
  /** Files auto-detect là thanh toán lô — chờ user xác nhận. */
  const [bulkDetectedFiles, setBulkDetectedFiles] = useState<File[]>([]);
  /** Chi tiết parse các file thanh toán lô để hiển thị ở tab preview. */
  const [parsedBatchPaymentDetails, setParsedBatchPaymentDetails] = useState<{ file: File; lines: BatchDetailLine[] }[]>([]);
  /** Các dòng sẽ đưa vào step 2 (CustomerGroupMatch) để batch-match. */
  const [pendingMatchRows, setPendingMatchRows] = useState<BankStatementImportRow[]>([]);
  /** Tên file sao kê hiện tại để truyền xuống step 2. */
  const [pendingFileName, setPendingFileName] = useState<string>('');

  // ── Parse batch payment files when batchPayments change ──
  React.useEffect(() => {
    if (batchPayments.length > 0) {
      // Parse cho API (service — CSV-based)
      parseBatchPaymentFiles(batchPayments).then(result => {
        setBatchDetailMap(result);
      });
      // Parse cho UI preview (XLSX-aware)
      Promise.all(
        batchPayments.map(async f => ({ file: f, lines: await parseBatchPaymentFileForDisplay(f) }))
      ).then(setParsedBatchPaymentDetails);
    } else {
      setBatchDetailMap(new Map());
      setParsedBatchPaymentDetails([]);
    }
  }, [batchPayments]);

  // ── Effective counts (skip + resolve) ──
  const effectiveReadyCount = useMemo(() => {
    if (!dryRunResult) return 0;
    let count = 0;
    for (const r of dryRunResult.rows) {
      if (r.status === 'error') continue;
      const resolution = customerResolutions.find(cr => cr.rowIndex === r.rowIndex);
      if (resolution?.skipOnImport) continue;
      if (r.status === 'missing_customer' && !resolution) continue;
      count++;
    }
    return count;
  }, [dryRunResult, customerResolutions]);

  const effectiveMissingCount = useMemo(() => {
    if (!dryRunResult) return 0;
    return dryRunResult.rows.filter(r => {
      if (r.status !== 'missing_customer') return false;
      const resolution = customerResolutions.find(cr => cr.rowIndex === r.rowIndex);
      return !resolution || !resolution.skipOnImport;
    }).length;
  }, [dryRunResult, customerResolutions]);

  const effectiveSkipCount = useMemo(() => {
    if (!dryRunResult) return 0;
    return customerResolutions.filter(r => r.skipOnImport).length;
  }, [customerResolutions]);

  // ── File parsing — progressive (chunk 50 rows, yield giữa các chunk) ────────

  /**
   * Parse file với progressive loading: xử lý từng chunk 50 rows và gọi
   * `onChunk` sau mỗi chunk để UI có thể cập nhật ngay lập tức (line-by-line).
   */
  const parseFileWithProgress = useCallback(async (
    file: File,
    onChunk: (loadedRows: BankStatementImportRow[], totalRawCount: number) => void,
  ): Promise<{
    rows: BankStatementImportRow[];
    headers: string[];
    rawData: Record<string, string>[];
    detectedTemplate: BankStatementTemplateType;
  }> => {
    const CHUNK_SIZE = 50;
    const buffer = await file.arrayBuffer();
    let headers: string[] = [];
    let detectedTemplate: BankStatementTemplateType = 'bao_no';

    // ── CSV branch ────────────────────────────────────────────────
    if (file.name.endsWith('.csv')) {
      const text = new TextDecoder('utf-8').decode(buffer);
      const lines = text.split('\n').filter(Boolean);
      headers = lines[0].split(',').map(h => h.trim());
      const rawRows: Record<string, string>[] = lines.slice(1).map(line => {
        const vals = line.split(',').map(v => v.trim());
        const row: Record<string, string> = {};
        headers.forEach((h, i) => { row[h] = vals[i] || ''; });
        return row;
      });
      detectedTemplate = detectTemplateType(headers, file.name);

      // Chunk processing cho CSV
      const allRows: BankStatementImportRow[] = [];
      for (let i = 0; i < rawRows.length; i += CHUNK_SIZE) {
        const chunk = rawRows.slice(i, i + CHUNK_SIZE);
        const mapped = chunk.map((raw, j) => mapRawToImportRow(raw, i + j));
        allRows.push(...mapped);
        onChunk([...allRows], rawRows.length);
        await new Promise<void>(resolve => setTimeout(resolve, 0));
      }
      return { rows: allRows, headers, rawData: rawRows, detectedTemplate };
    }

    // ── XLSX branch ───────────────────────────────────────────────
    const workbook = XLSX.read(buffer, { type: 'array' });
    const sheetName = workbook.SheetNames[0];
    const sheet = workbook.Sheets[sheetName];
    const json = XLSX.utils.sheet_to_json<string[]>(sheet, { header: 1, defval: '' });

    if (!json || json.length === 0) {
      return { rows: [], headers: [], rawData: [], detectedTemplate };
    }

    // Detect header row
    let headerRowIndex = -1;
    const HEADER_KEYWORDS = [
      'stt', 'ngày giao dịch', 'số bút toán', 'transaction date', 'transaction no',
      'phát sinh nợ', 'phát sinh có', 'debit', 'credit', 'nội dung', 'details',
      'số tiền', 'amount', 'diễn giải', 'mô tả', 'mã ct',
      'đơn vị thụ hưởng', 'beneficiary', 'tài khoản', 'account',
    ];
    for (let i = 0; i < Math.min(json.length, 50); i++) {
      const row = json[i];
      if (!row) continue;
      const nonEmpty = row.filter((c: string) => c).length;
      if (nonEmpty < 3) continue;
      const rowText = row.filter((c: string) => c).join(' ').toLowerCase();
      const matchCount = HEADER_KEYWORDS.filter(kw => rowText.includes(kw)).length;
      if (matchCount >= 3) { headerRowIndex = i; break; }
    }
    if (headerRowIndex === -1) {
      for (let i = 0; i < Math.min(json.length, 20); i++) {
        if (json[i].some((c: string) => c)) { headerRowIndex = i; break; }
      }
    }
    if (headerRowIndex === -1) {
      return { rows: [], headers: [], rawData: [], detectedTemplate };
    }

    const headerRow = json[headerRowIndex].map((h: string) => String(h).trim());
    headers = headerRow.map(h => h.replace(/\r?\n.*$/, '').trim());
    const columnMap = detectColumnMap(headers);
    detectedTemplate = detectTemplateType(headers, file.name);

    // Collect rawData (fast scan — chỉ extract giá trị raw)
    const rawData: Record<string, string>[] = [];
    for (let i = headerRowIndex + 1; i < json.length; i++) {
      const row = json[i];
      if (!row || (row as string[]).every((c: string) => !c)) continue;
      const sttVal = String(row[columnMap.sttIndex] || '').trim();
      if (sttVal && columnMap.sttIndex >= 0) {
        const raw: Record<string, string> = {};
        raw['STT'] = sttVal;
        raw['Ngày giao dịch'] = String(row[columnMap.dateIndex] || '').trim();
        raw['Số bút toán'] = String(row[columnMap.refIndex] || '').trim();
        raw['Phát sinh nợ'] = String(row[columnMap.debitIndex] || '').trim();
        raw['Phát sinh có'] = String(row[columnMap.creditIndex] || '').trim();
        raw['Nội dung'] = String(row[columnMap.descriptionIndex] || '').trim();
        raw['Đơn vị thụ hưởng/Đơn vị chuyển'] = columnMap.beneficiaryIndex >= 0 ? String(row[columnMap.beneficiaryIndex] || '').trim() : '';
        raw['Tài khoản'] = columnMap.accountIndex >= 0 ? String(row[columnMap.accountIndex] || '').trim() : '';
        rawData.push(raw);
      }
    }

    // Chunk processing — yield sau mỗi 50 rows để UI update ngay
    const allRows: BankStatementImportRow[] = [];
    for (let i = 0; i < rawData.length; i += CHUNK_SIZE) {
      const chunk = rawData.slice(i, i + CHUNK_SIZE);
      const mapped = chunk.map((raw, j) => mapRawToImportRow(raw, i + j));
      allRows.push(...mapped);
      onChunk([...allRows], rawData.length);
      // Yield to browser — cho phép React render trước khi tiếp tục
      await new Promise<void>(resolve => setTimeout(resolve, 0));
    }

    return { rows: allRows, headers, rawData, detectedTemplate };
  }, []);

  // ── Step 1 callbacks ─────────────────────────────────────────

  /**
   * Nhận File[] từ Step1Upload (sau khi conflict đã được resolve).
   * `overrideIndices`: index các file cũ cần xoá trước khi add file mới (ghi đè).
   */
  const handleBankStatementSelect = useCallback(async (files: File[], overrideIndices?: number[]) => {
    // Xoá các file đang bị ghi đè (desc để không bị lệch index)
    if (overrideIndices && overrideIndices.length > 0) {
      const sorted = [...overrideIndices].sort((a, b) => b - a);
      setBankStatements(prev => {
        let updated = [...prev];
        for (const idx of sorted) {
          updated = updated.filter((_, i) => i !== idx);
        }
        return updated;
      });
    }

    // ── Phát hiện file thanh toán lô trước khi parse ──────────────────────────
    const bulkFiles: File[] = [];
    const normalFiles: File[] = [];
    for (const f of files) {
      const isBulk = await detectIsBulkPaymentFileQuick(f);
      if (isBulk) bulkFiles.push(f);
      else normalFiles.push(f);
    }
    if (bulkFiles.length > 0) {
      setBulkDetectedFiles(prev => [...prev, ...bulkFiles]);
    }

    // Parse chỉ các file sao kê bình thường
    for (const f of normalFiles) {
      setParseProgress({ fileName: f.name, loaded: 0, total: 0 });
      setPartialRows([]);
      try {
        const result = await parseFileWithProgress(f, (loadedRows, totalCount) => {
          setParseProgress({ fileName: f.name, loaded: loadedRows.length, total: totalCount });
          setPartialRows(loadedRows);
        });
        setBankStatements(prev => [...prev, { file: f, ...result }]);
      } catch {
        // ignore lỗi file đơn lẻ
      }
    }
    setParseProgress(null);
    setPartialRows([]);
  }, [parseFileWithProgress]);

  /** User xác nhận chuyển bulk files → batchPayments. */
  const handleBulkConfirm = useCallback((files: File[]) => {
    setBatchPayments(prev => [...prev, ...files]);
    setBulkDetectedFiles([]);
  }, []);

  /** User từ chối — bỏ qua bulk files đã detect. */
  const handleBulkReject = useCallback(() => {
    setBulkDetectedFiles([]);
  }, []);

  const handleBankStatementRemove = useCallback((index: number) => {
    setBankStatements(prev => prev.filter((_, i) => i !== index));
  }, []);

  const handleBatchPaymentAdd = useCallback((files: File[]) => {
    setBatchPayments(prev => [...prev, ...files]);
  }, []);

  const handleBatchPaymentRemove = useCallback((index: number) => {
    setBatchPayments(prev => prev.filter((_, i) => i !== index));
  }, []);

  /**
   * Smart folder import — dùng khi user chọn folder (cả 2 zone) hoặc drop folder.
   * Tự phát hiện file loại nào → route đúng zone, KHÔNG show confirm panel.
   * - File thanh toán lô → batchPayments (useEffect sẽ tự parse preview)
   * - File sao kê → parse như thường
   */
  const handleSmartFolderImport = useCallback(async (files: File[]) => {
    const ALLOWED = ['.xlsx', '.xls', '.csv'];
    const supported = files.filter(f =>
      ALLOWED.some(ext => f.name.toLowerCase().endsWith(ext))
    );
    if (supported.length === 0) return;

    const batchFiles: File[] = [];
    const normalFiles: File[] = [];
    for (const f of supported) {
      const isBulk = await detectIsBulkPaymentFileQuick(f);
      if (isBulk) batchFiles.push(f);
      else normalFiles.push(f);
    }

    // Batch files → add to batchPayments (useEffect auto-parses preview)
    if (batchFiles.length > 0) {
      setBatchPayments(prev => [...prev, ...batchFiles]);
    }

    // Normal files → parse as sao kê (không chạy detection lần 2)
    for (const f of normalFiles) {
      setParseProgress({ fileName: f.name, loaded: 0, total: 0 });
      setPartialRows([]);
      try {
        const result = await parseFileWithProgress(f, (loadedRows, totalCount) => {
          setParseProgress({ fileName: f.name, loaded: loadedRows.length, total: totalCount });
          setPartialRows(loadedRows);
        });
        setBankStatements(prev => [...prev, { file: f, ...result }]);
      } catch {
        // ignore lỗi file đơn lẻ
      }
    }
    setParseProgress(null);
    setPartialRows([]);
  }, [parseFileWithProgress]);

  // ── Step 1 → 2: Group Match ────────────────────────────────

  const handleStep1Next = useCallback(async () => {
    if (bankStatements.length === 0) {
      dispatchAppToast(dispatch, { message: 'Vui lòng chọn file sao kê ngân hàng.', type: 'warning' });
      return;
    }

    const fileName = bankStatements[0].file.name;
    let allRows = bankStatements[0].rows
      .map((r, idx) => {
        const hasDebit = r.debitAmount !== undefined && r.debitAmount > 0;
        const hasCredit = r.creditAmount !== undefined && r.creditAmount > 0;
        return {
          ...r,
          rowIndex: idx,
          suggestedVoucherType: (hasDebit ? 'bao_no' : hasCredit ? 'bao_co' : undefined) as 'bao_no' | 'bao_co' | undefined,
          importReference: `Import:${fileName}:${idx + 1}${r.description ? ` - ${r.description.slice(0, 60)}` : ''}`,
        };
      });

    if (skipEmptyRows) {
      allRows = allRows.filter(r => r.amount !== undefined && r.amount !== null && r.amount > 0);
    }

    if (allRows.length === 0) {
      dispatchAppToast(dispatch, { message: 'File sao kê không có dữ liệu hợp lệ. Vui lòng kiểm tra lại.', type: 'warning' });
      return;
    }

    // Extract batch refs
    const rowsWithBatchRefs = allRows.map(r => ({
      ...r,
      detectedBatchRefs: extractBulkRefsFromDescription(r.description),
    }));

    // Chuyển sang step 2 — matchCustomers được gọi bên trong CustomerGroupMatch (batch 100, có progress)
    setPendingMatchRows(rowsWithBatchRefs);
    setPendingFileName(fileName);
    setMatchResult(null);
    setStep(2);
  }, [bankStatements, skipEmptyRows]);

  // ── Step 2 (Group Match Confirm) → Step 3 (Dry Run) ───────

  const handleGroupMatchConfirm = useCallback(async (resolutions: CustomerResolution[]) => {
    if (bankStatements.length === 0) return;

    setCustomerResolutions(resolutions);
    setLoading(true);

    const fileName = bankStatements[0].file.name;
    let allRows = bankStatements[0].rows
      .map((r, idx) => {
        const hasDebit = r.debitAmount !== undefined && r.debitAmount > 0;
        const hasCredit = r.creditAmount !== undefined && r.creditAmount > 0;
        return {
          ...r,
          rowIndex: idx,
          suggestedVoucherType: (hasDebit ? 'bao_no' : hasCredit ? 'bao_co' : undefined) as 'bao_no' | 'bao_co' | undefined,
          importReference: `Import:${fileName}:${idx + 1}${r.description ? ` - ${r.description.slice(0, 60)}` : ''}`,
        };
      });

    if (skipEmptyRows) {
      allRows = allRows.filter(r => r.amount !== undefined && r.amount !== null && r.amount > 0);
    }

    const rowsWithBatchRefs = allRows.map(r => ({
      ...r,
      detectedBatchRefs: extractBulkRefsFromDescription(r.description),
    }));

    try {
      const result = await bankStatementImportService.dryRun({
        monthCode: getCurrentMonthCode(),
        bankStatementFile: fileName,
        batchPaymentFiles: batchPayments.map(f => f.name),
        rows: rowsWithBatchRefs,
        skipEmptyRows,
      });
      setDryRunResult(result);
      setStep(3);

      if (result.missingCustomerCount > 0) {
        dispatchAppToast(dispatch, {
          message: `${result.missingCustomerCount} dòng vẫn thiếu khách hàng sau group match — vui lòng kiểm tra.`,
          type: 'info',
        });
      }
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Lỗi khi phân tích file. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setLoading(false);
    }
  }, [bankStatements, skipEmptyRows, dispatch]);

  // ── Handle back from group match step ────────────
  const handleGroupMatchBack = useCallback(() => {
    setStep(1);
    setMatchResult(null);
    setPendingMatchRows([]);
    setPendingFileName('');
  }, []);

  // ── Import execution — batch processing ──────────────────────

  const handleImport = useCallback(async () => {
    if (!dryRunResult) return;

    const total = dryRunResult.readyCount;
    setImportProgress({ total, done: 0, errors: [], running: true, finished: false, duplicateSkipped: 0, perRowStatus: {} });
    setLoading(true);

    try {
      // Compute skip indices from resolutions
      const skipRowIndices = customerResolutions
        .filter(r => r.skipOnImport)
        .map(r => r.rowIndex);

      const result = await bankStatementImportService.executeImport({
        dryRunId: dryRunResult.dryRunId,
        customerResolutions,
        batchSize: IMPORT_BATCH_SIZE,
        skipRowIndices: skipRowIndices.length > 0 ? skipRowIndices : undefined,
      });

      // Build per-row status map
      const perRowStatus: Record<number, { status: string; voucherCode?: string; errorMessage?: string }> = {};
      for (const r of result.rowResults) {
        perRowStatus[r.rowIndex] = {
          status: r.status,
          voucherCode: r.voucherCode,
          errorMessage: r.errorMessage,
        };
      }

      setImportResult(result);
      setImportProgress({
        total: result.totalRows,
        done: result.successCount + result.errorCount,
        errors: result.rowResults.filter(r => r.status === 'error').map(r => r.errorMessage || ''),
        running: false,
        finished: true,
        duplicateSkipped: result.duplicateSkippedCount,
        perRowStatus,
      });
    } catch (err: unknown) {
      setImportProgress(prev => ({
        ...prev,
        running: false,
        finished: true,
        errors: [...prev.errors, getApiErrorMessage(err, 'Lỗi không xác định')],
      }));
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Lỗi import. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setLoading(false);
    }
  }, [dryRunResult, customerResolutions, dispatch]);

  const handleRetry = useCallback(() => {
    if (!importResult) return;
    setImportResult(null);
    setImportProgress({ total: 0, done: 0, errors: [], running: false, finished: false, duplicateSkipped: 0 });
    dispatchAppToast(dispatch, { message: 'Đã xoá lỗi, có thể import lại.', type: 'info' });
  }, [importResult, dispatch]);

  const handleFinish = useCallback(() => {
    setStep(1);
    setBankStatements([]);
    setBatchPayments([]);
    setMatchResult(null);
    setDryRunResult(null);
    setCustomerResolutions([]);
    setImportResult(null);
    setImportProgress({ total: 0, done: 0, errors: [], running: false, finished: false, duplicateSkipped: 0 });
    dispatchAppToast(dispatch, { message: 'Import hoàn tất.', type: 'success' });
  }, [dispatch]);

  // ── Render ───────────────────────────────────────────────────

  return (
    <div className={styles.page}>
      {/* Step indicator */}
      <div className={styles.steps}>
        {([1, 2, 3, 4] as ImportStep[]).map(s => (
          <div key={s} className={`${styles.stepItem} ${step === s ? styles.stepActive : ''} ${step > s ? styles.stepDone : ''}`}>
            <div className={styles.stepNumber}>{step > s ? '✓' : s}</div>
            <div className={styles.stepLabel}>
              {s === 1 ? 'Chọn file' : s === 2 ? 'Xác nhận KH' : s === 3 ? 'Phân tích' : 'Import'}
            </div>
          </div>
        ))}
      </div>

      {/* Loading skeleton */}
      {loading && (
        <div className={styles.loadingOverlay}>
          <ImportSkeleton rows={8} />
        </div>
      )}

      {!loading && (
        <>
        {step === 1 && (
        <Step1Upload
          bankStatements={bankStatements as any}
          batchPayments={batchPayments}
          skipEmptyRows={skipEmptyRows}
          onSkipEmptyRowsChange={setSkipEmptyRows}
          onBankStatementSelect={handleBankStatementSelect}
          onBankStatementRemove={handleBankStatementRemove}
          onBatchPaymentAdd={handleBatchPaymentAdd}
          onBatchPaymentRemove={handleBatchPaymentRemove}
          onSmartFolderImport={handleSmartFolderImport}
          onNext={handleStep1Next}
          parseProgress={parseProgress}
          partialRows={partialRows}
          bulkDetectedFiles={bulkDetectedFiles}
          onBulkConfirm={handleBulkConfirm}
          onBulkReject={handleBulkReject}
          parsedBatchPaymentDetails={parsedBatchPaymentDetails}
        />
      )}

      {step === 2 && pendingMatchRows.length > 0 && (
        <CustomerGroupMatch
          rows={pendingMatchRows}
          fileName={pendingFileName}
          onConfirm={handleGroupMatchConfirm}
          onBack={handleGroupMatchBack}
        />
      )}

      {step === 3 && dryRunResult && (
        <Step2DryRun
          dryRunResult={dryRunResult}
          resolutions={customerResolutions}
          onResolutionsChange={setCustomerResolutions}
          onNext={() => setStep(4)}
          onBack={() => setStep(2)}
          batchDetailMap={batchDetailMap}
        />
      )}

      {step === 4 && dryRunResult && (
        <Step4ConfirmImport
          totalRows={dryRunResult.totalRows}
          readyCount={effectiveReadyCount}
          missingCustomerCount={effectiveMissingCount}
          onImport={handleImport}
          importResult={importResult}
          importProgress={importProgress}
          onRetry={handleRetry}
          onFinish={handleFinish}
          onBack={() => setStep(3)}
          dryRunRows={dryRunResult.rows}
          customerResolutions={customerResolutions}
        />
      )}
      </>)}
    </div>
  );
};

// ── Helpers (unchanged) ──────────────────────────────────────────────────────

interface ColumnMap {
  sttIndex: number;
  dateIndex: number;
  refIndex: number;
  debitIndex: number;
  creditIndex: number;
  descriptionIndex: number;
  beneficiaryIndex: number;
  accountIndex: number;
}

function detectColumnMap(headers: string[]): ColumnMap {
  const idx = (keywords: string[], notKeywords?: string[]) => {
    for (let i = 0; i < headers.length; i++) {
      const h = headers[i].toLowerCase().replace(/[\r\n]+/g, ' ').trim();
      const hasKeyword = keywords.some(kw => h.includes(kw));
      if (!hasKeyword) continue;
      if (notKeywords && notKeywords.some(nk => h.includes(nk))) continue;
      return i;
    }
    return -1;
  };

  return {
    sttIndex: idx(['stt', 'no', 'số tt'], ['số bút toán', 'số ct', 'transaction no']),
    dateIndex: idx(['ngày giao dịch', 'ngày', 'date', 'transaction date']),
    refIndex: idx(['số bút toán', 'transaction no', 'mã giao dịch', 'số ct', 'reference']),
    debitIndex: idx(['phát sinh nợ', 'debit', 'nợ'], ['phát sinh có', 'credit']),
    creditIndex: idx(['phát sinh có', 'credit', 'có'], ['phát sinh nợ', 'debit']),
    descriptionIndex: idx(['nội dung', 'details', 'diễn giải', 'mô tả', 'description']),
    beneficiaryIndex: idx(['đơn vị thụ hưởng', 'beneficiary', 'đối tượng', 'ncc', 'kh']),
    accountIndex: idx(['tài khoản', 'account'], ['ngân hàng đối tác', 'remitter bank']),
  };
}

function mapRawToImportRow(raw: Record<string, string>, index: number): BankStatementImportRow {
  const val = (...keys: string[]) => {
    for (const k of keys) {
      const v = raw[k] || raw[k.toLowerCase()] || raw[k.toUpperCase()];
      if (v) return v;
    }
    return '';
  };

  const parseAmount = (v: string): number | undefined => {
    if (!v) return undefined;
    let cleaned = String(v).trim().replace(/\s/g, '');
    if (!cleaned) return undefined;

    const hasComma = cleaned.includes(',');
    const dotCount = (cleaned.match(/\./g) || []).length;

    if (hasComma && dotCount > 0) {
      const lastComma = cleaned.lastIndexOf(',');
      const lastDot = cleaned.lastIndexOf('.');
      if (lastComma > lastDot) {
        cleaned = cleaned.replace(/\./g, '');
        const lc = cleaned.lastIndexOf(',');
        cleaned = cleaned.substring(0, lc) + '.' + cleaned.substring(lc + 1);
      } else {
        cleaned = cleaned.replace(/,/g, '');
      }
    } else if (hasComma) {
      cleaned = cleaned.replace(/,/g, '');
    } else if (dotCount > 1) {
      cleaned = cleaned.replace(/\./g, '');
    }

    const n = parseFloat(cleaned);
    return isNaN(n) ? undefined : n;
  };

  const debitAmount = parseAmount(val('Phát sinh nợ', 'Debit', 'Báo nợ', 'Chi'));
  const creditAmount = parseAmount(val('Phát sinh có', 'Credit', 'Báo có', 'Thu'));
  const description = val('Nội dung', 'Details', 'Diễn giải', 'Mô tả', 'Description');
  const counterpartyName = val('Đơn vị thụ hưởng/Đơn vị chuyển', 'Beneficiary/Applicant', 'Đối tượng', 'NCC', 'KH', 'Customer', 'Supplier');

  const postingCategory = detectPostingCategory(description, counterpartyName);

  return {
    rowIndex: index,
    transactionDate: val('Ngày giao dịch', 'Ngày GD', 'Ngày', 'Transaction Date', 'Date'),
    referenceCode: val('Số bút toán', 'Mã CT', 'Số CT', 'Transaction No', 'Reference', 'Mã giao dịch'),
    amount: pickAmount(debitAmount, creditAmount),
    debitAmount,
    creditAmount,
    suggestedVoucherType: (debitAmount ? 'bao_no' : creditAmount ? 'bao_co' : undefined) as 'bao_no' | 'bao_co' | undefined,
    counterpartyName,
    description,
    bankAccountCode: val('Tài khoản', 'Account', 'TK NH', 'TK ngân hàng', 'Bank Account'),
    customerCode: val('Mã KH', 'Mã NCC', 'Customer Code'),
    postingCategoryCode: postingCategory.code,
    postingCategoryLabel: postingCategory.label,
  };
}

function detectTemplateType(headers: string[], fileName: string): BankStatementTemplateType {
  const h = headers.map(h => h.toLowerCase().trim());
  const combined = [...h, fileName.toLowerCase()];
  if (combined.some(s => s.includes('unc') || s.includes('ủy nhiệm') || s.includes('uy nhiem'))) return 'unc';
  if (combined.some(s => s.includes('chuyển tiền') || s.includes('chuyen tien') || s.includes('ctnb'))) return 'ctnb';
  if (combined.some(s => s.includes('báo có') || s.includes('bao co') || s.includes('credit'))) return 'bao_co';
  return 'bao_no';
}

function getCurrentMonthCode(): string {
  const d = new Date();
  return `${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, '0')}`;
}

function pickAmount(debit?: number, credit?: number): number | undefined {
  if (debit && debit > 0) return debit;
  if (credit && credit > 0) return credit;
  return debit || credit || undefined;
}

export default ImportSaoKePage;
