// ── GAP-IMP-P1-02/P1-03: Batch resolve + validate

interface BatchResolveRow {
  rowIndex: number;
  supplierName?: string;
  bankAccount?: string;
  taxCode?: string;
}

interface BatchValidateRow {
  rowIndex: number;
  sourceRef?: string;
  accountCode?: string;
  transactionDate?: string;
}

interface BatchResolveResult {
  rowIndex: number;
  supplierId?: string;
  supplierCode?: string;
  supplierName?: string;
  confidence: number;
}

interface BatchValidateResult {
  rowIndex: number;
  valid: boolean;
  warnings?: string[];
  duplicateSourceRef?: boolean;
}

/** GAP-IMP-P1-02: Resolve NCC theo batch */
export async function resolveBatch(rows: BatchResolveRow[]): Promise<BatchResolveResult[]> {
  try {
    const res = await apiClient.post<BffResponse<{ results: BatchResolveResult[] }>>(`${BASE}/resolve-batch`, { rows });
    return (await unwrap(res)).results;
  } catch {
    return rows.map(r => ({ rowIndex: r.rowIndex, confidence: 0 }));
  }
}

/** GAP-IMP-P1-03: Validate rows theo batch */
export async function validateBatch(rows: BatchValidateRow[]): Promise<BatchValidateResult[]> {
  try {
    const res = await apiClient.post<BffResponse<{ results: BatchValidateResult[] }>>(`${BASE}/validate-batch`, { rows });
    return (await unwrap(res)).results;
  } catch {
    return rows.map(r => ({ rowIndex: r.rowIndex, valid: true }));
  }
}

/** GAP-IMP-P2-06: Download template file */
export async function downloadTemplate(voucherKind: string): Promise<void> {
  const blob = await apiClient.getBlob(`${BASE}/template?voucherKind=${voucherKind}`);
  const url = window.URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `mau-import-${voucherKind}.xlsx`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  window.URL.revokeObjectURL(url);
}





